import './App.css';

import { createBrowserHistory } from 'history';
import cookies from 'react-cookies';
import { Navbar, Nav, NavDropdown, Container } from 'react-bootstrap';
import { Router, Switch, Route} from 'react-router-dom';
import StartPage from './components/StartPage';
import LoginPage from './components/login/LoginPage';
import Overview from './components/Overview';
import Service from './components/service/Service';
import Reservation from './components/reservation/Reservation';
import Statistics from './components/statistics/Statistics';
import Order from './components/service/Order';
import Kitchen from './components/kitchen/Kitchen';
import KitchenOverview from './components/kitchen/KitchenOverview';
import ManagmentOverview from './components/management/ManagmentOverview';
import WaiterOverview from './components/management/WaiterOverview';
import TableOverview from './components/management/TableOverview';
import Deliver from './components/kitchen/Deliver';
import FoodOverview from './components/management/FoodOverview';
import DrinkOverview from './components/management/DrinkOverview';
import LogoutPage from './components/logout/LogoutPage';
import KitchenDrinks from './components/kitchen/KitchenDrinks';
import KitchenPrepareOverview from './components/kitchen/KitchenPrepareOverview';
import Profile from './components/profile/Profile'
import NoPage from './components/NoPage';
import Menu from './components/Menu';
import ResturantOverview from './components/management/ResturantOverview';
import Title from './components/Title';



const history = createBrowserHistory();

function App() {
	cookies.loadAll();
	return (
		<Router basename="/" history={history}>
			<div>
				<Navbar collapseOnSelect  bg="dark" variant="dark" expand="lg" fixed="top" className='bg-body-tertiary'>
					<Container>
						<Title />
						<Navbar.Toggle aria-controls="responsive-navbar-nav" />
						<Navbar.Collapse id="justify-content-end">
							<Nav className="me-auto">
								{ (cookies.load("username") === undefined) ?
									<Nav.Link href="/login">
										Login
									</Nav.Link>
									: null
								}
								{(cookies.load("username") !== undefined) ? 
									<Nav.Link href="/app/overview">
										Übersicht
									</Nav.Link>	
									: null
								}
							</Nav>
							<Nav>
								{ (cookies.load("username") !== undefined) ?
									<div className="NavbarLoggedIn">
										<NavDropdown title={cookies.load("name")}>
											<NavDropdown.Item href='/app/profile'>
												Profile
											</NavDropdown.Item>
											<NavDropdown.Item href='/logout'>
												Logout
											</NavDropdown.Item>
										</NavDropdown>
									</div>
									: null
								}
							</Nav>
						</Navbar.Collapse>
					</Container>
				</Navbar>
				<Switch>
					<Route exact path="/">
						<StartPage />
					</Route>
					<Route path="/login">
						<LoginPage />
					</Route>
					<Route path="/logout">
						<LogoutPage />
					</Route>
					<Route path="/app/service/order/:idTable/:name/:personCount" component={Order} />
					<Route path="/app/service">
						<Service />
					</Route>
					<Route path="/app/kitchen/prepare/food">
						<Kitchen />
					</Route>
					<Route path="/app/kitchen/prepare/drinks">
						<KitchenDrinks />
					</Route>
					<Route path="/app/kitchen/prepare">
						<KitchenPrepareOverview />
					</Route>
					<Route path="/app/kitchen/deliver">
						<Deliver />
					</Route>
					<Route path="/app/kitchen">
						<KitchenOverview />
					</Route>
					<Route path="/app/reservation">
						<Reservation />
					</Route>
					<Route path="/app/statistics">
						<Statistics />
					</Route>
					<Route path="/app/overview">
						<Overview />
					</Route>
					<Route path="/app/managment/info">
						<ResturantOverview />
					</Route>
					<Route path="/app/managment/waiter">
						<WaiterOverview />
					</Route>
					<Route path="/app/managment/table">
						<TableOverview />
					</Route>
					<Route path="/app/managment/food">
						<FoodOverview />
					</Route>
					<Route path="/app/managment/drink">
						<DrinkOverview />
					</Route>
					<Route path="/app/managment">
						<ManagmentOverview />
					</Route>
					<Route path="/app/profile">
						<Profile />
					</Route>
					<Route path="/menu">
						<Menu />
					</Route>
					<Route path="*">
						<NoPage />
					</Route>
				</Switch>
			</div>
		</Router>
	);
}

export default App;