import React, { Component } from "react";
import { Alert, Breadcrumb, Button, Col, Container, Form, InputGroup, Row } from "react-bootstrap";
import cookies from 'react-cookies';
import { serverip } from "../config";
import { FiEye, FiEyeOff } from "react-icons/fi";

class Profile extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		this.state = {
			userData: [],
			roles: [],
			showPasswordCurrent: false,
			showPasswordNew: false,
			showPasswordNewRepeat: false
		}

		document.title = `Profil - - ${cookies.load("title")}`;
	}

	componentDidMount() {
		this.getProfileInfo();
		this.getRoles();
	}

	async getProfileInfo() {
		await fetch(serverip + `/waiter/get/byUsername/${cookies.load("username")}`)
        .then(response => response.json())
        .then(data =>
			this.setState({ userData: data[0] })
		);
	}

	async getRoles(){
		await fetch(serverip + "/waiter/roles/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ roles: data })
		);
	}

	showRoles(roleJson) {
		let result = "";
		
		if(roleJson === undefined)
			return "";

		roleJson = JSON.parse(roleJson).granted;
		
		roleJson.forEach(role => {
			this.state.roles.forEach((roleInfo) => {
				if(roleInfo.idRole === role)
					result += `${roleInfo.name}, `;
			});
		});

		return result.substring(0, result.length -2);
	}

	roleCount(roleJson) {
		if(roleJson === undefined)
			return "";
		return Math.ceil(JSON.parse(roleJson).granted.length / 2);
	}
	
	switchCurrentPasswordVisibilty(state) {
		this.setState({
			showPasswordCurrent: state
		});
	}

	switchNewPasswordVisibilty(state) {
		this.setState({
			showPasswordNew: state
		});
	}

	switchNewRepeatPasswordVisibilty(state) {
		this.setState({
			showPasswordNewRepeat: state
		});
	}

	render() {
		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Profil
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<h1>Profil von {cookies.load("name")}</h1>
				<Container>
					<Row>
						<Col>
							<Row>
								<Col>
									<Form.Group className="mb-3">
										<Form.Label>
											Name
										</Form.Label>
										<Form.Control defaultValue={this.state.userData.name} />
									</Form.Group>
								</Col>
							</Row>
							<Row>
								<Col>
									<Form.Group className="mb-3">
										<Form.Label>
											Username
										</Form.Label>
										<Form.Control defaultValue={this.state.userData.username} />
									</Form.Group>
								</Col>
							</Row>
							<Row>
								<Col>
									<Button variant="success">
										Daten speichern
									</Button>
								</Col>
							</Row>
						</Col>
						<Col>
							<Row>
								<Col>
									<Form.Group className="mb-3">
										<Form.Label>
											Aktuelles Passwort
										</Form.Label>
										<InputGroup>
											<Form.Control type={(this.state.showPasswordCurrent) ? "text" : "password"} defaultValue={this.state.userData.password} />
											<Button variant="secondary" onClick={() => {this.switchCurrentPasswordVisibilty(!this.state.showPasswordCurrent)}}>
												{(this.state.showPasswordCurrent) ? <FiEye /> : <FiEyeOff />}
											</Button>
										</InputGroup>
									</Form.Group>
								</Col>
							</Row>
							<Row>
								<Col>
									<Form.Group className="mb-3">
										<Form.Label>
											Neues Passwort
										</Form.Label>
										<InputGroup>
											<Form.Control type={(this.state.showPasswordNew) ? "text" : "password"} />
											<Button variant="secondary" onClick={() => {this.switchNewPasswordVisibilty(!this.state.showPasswordNew)}}>
												{(this.state.showPasswordNew) ? <FiEye /> : <FiEyeOff />}
											</Button>
										</InputGroup>
									</Form.Group>
								</Col>
							</Row>
							<Row>
								<Col>
									<Form.Group className="mb-3">
										<Form.Label>
											Neues Passwort wiederholen
										</Form.Label>
										<InputGroup>
											<Form.Control type={(this.state.showPasswordNewRepeat) ? "text" : "password"} />
											<Button variant="secondary" onClick={() => {this.switchNewRepeatPasswordVisibilty(!this.state.showPasswordNewRepeat)}}>
												{(this.state.showPasswordNewRepeat) ? <FiEye /> : <FiEyeOff />}
											</Button>
										</InputGroup>
									</Form.Group>
								</Col>
							</Row>
							<Row>
								<Col>
									<Button variant="success">
										Neues Passwort speichern
									</Button>
								</Col>
							</Row>
						</Col>
					</Row>
					<Row>
						<Col>
							<Form.Group className="mb-3">
								<Form.Label>
									Berechtigungen
								</Form.Label>
								<Form.Control as="textarea" rows={this.roleCount(this.state.userData.roles)} value={this.showRoles(this.state.userData.roles)} readOnly />
							</Form.Group>
						</Col>
					</Row>
				</Container>
				
			</div>
		);
	}
} 

export default Profile;