import React, { Component } from "react";
import { Card, Button, InputGroup, Breadcrumb, Alert, ButtonGroup, Modal, Placeholder, Badge, Dropdown } from "react-bootstrap";
import { serverip } from "../config";
import cookies from 'react-cookies';
import { FiTrash2, FiPlus, FiMinus, FiSend, FiClock, FiBell, FiBellOff, FiMenu, FiMusic } from 'react-icons/fi';

class KitchenDrinks extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		this.state = {
			orderInfo: [],
			showDeleteModal: false,
			deleteOrderId: -1,
			isLoading: true,
			soundOn: true,
			sounds: ['bell', 'chime'],
			selectedSound: 'bell'
		}

		document.title = `Trinken - ${cookies.load("title")}`;
	}

	componentDidMount() {
		this.refresh();
	}

	refresh() {
		this.getOrder();
		
		setTimeout(() => {
			this.refresh();
		}, 10000);
	}

	async getOrder() {
		await fetch(serverip + "/order/todo/all")
        .then(response => response.json())
        .then(data =>{
			this.setState({ orderInfo: [] });
			this.setState({ 
				orderInfo: data,
				isLoading: false
			});
		});
	}

	addDrinkButton(id, drinkName, order) {
		let drinkText = document.getElementById(id);
		let json = JSON.parse(order.foodOrder);

		json.order.forEach(drink => {
			if(drink.drink.name === drinkName)
				if(drink.drink.done < drink.drink.count)
				{
					drinkText.innerHTML = `<b>${drink.drink.done + 1} / ${drink.drink.count}</b>`;

					drink.drink.done += 1;
					order.foodOrder = JSON.stringify(json);
					
					this.updateOrderDoing(order.idOrder, JSON.stringify(json));
				}
		});
	}

	removeDrinkButton(id, drinkName, order) {
		let drinkText = document.getElementById(id);
		let json = JSON.parse(order.foodOrder);

		json.order.forEach(drink => {
			if(drink.drink.name === drinkName)
				if(drink.drink.done > 0)
				{
					drinkText.innerHTML = `<b>${drink.drink.done - 1} / ${drink.drink.count}</b>`;

					drink.drink.done -= 1;
					order.foodOrder = JSON.stringify(json);
					
					this.updateOrderDoing(order.idOrder, JSON.stringify(json));
				}
		});
	}

	isOrderReady(order) {
		let unReady = false;

		order.order.forEach(drink => {
			if(parseInt(drink.drink.done) !== parseInt(drink.drink.count))
				unReady = true;
		});

		return unReady;
	}

	timestampToTime(timestamp) {
		return Number((Date.now() - timestamp) / 1000 / 60).toFixed(0);
	}

	async updateOrderDoing(idOrder, order) {
        await fetch(serverip + `/order/update/${idOrder}/${encodeURI(order)}`, {
			method: 'PUT'
		});
	}

	async completeOrder(idOrder) {
        await fetch(serverip + `/order/done/${idOrder}/1`, {
			method: 'PUT'
		});

        this.getOrder();
    }

	async deleteOrderCall(idOrder) {
        await fetch(serverip + "/order/delete/" + idOrder, {
			method: 'DELETE'
		});

		await fetch(serverip + `/order/hasTable/delete/${idOrder}`, {
			method: "DELETE"
		});

		this.getOrder();
    }

	deleteOrder(idOrder) {
		this.setState({
			deleteOrderId: idOrder,
			showDeleteModal: true
		});
	}

	saveDeleteOrder() {
		this.deleteOrderCall(this.state.deleteOrderId);

		this.handleDeleteModal(false);
	}

	checkWaitingTime(timestamp) {

		let diff = Number((Date.now() - timestamp) / 1000 / 60).toFixed(0);

		if(diff < 15)
			return "info";
		else if(diff >= 15 && diff < 30)
			return "warning";
		else
			return "danger";
	}

	handleDeleteModal(state) {
		this.setState({
			showDeleteModal: state
		});
	}

	hasDrinkOrder() {
		let drinkCounter = 0;

		this.state.orderInfo.forEach(order => {

			if(JSON.parse(order.foodOrder).type === "drinks")
				drinkCounter ++;
		});

		return (drinkCounter === 0) ? true : false;
	}

	countDrinkOrder() {
		let drinkCounter = 0;

		this.state.orderInfo.forEach(order => {

			if(JSON.parse(order.foodOrder).type === "drinks")
				drinkCounter ++;
		});

		return drinkCounter;
	}

	sendPingIfNewOrder(timestamp) {

		if(!this.state.soundOn)
			return;

		if(((Date.now() - timestamp) / 1000) < 8) {
			this.playAudio();
		}
	}

	muteSound() {
		let isSoundOn = this.state.soundOn;

		this.setState({
			soundOn: !isSoundOn
		});
	}

	playAudio() {
		let audio = new Audio();

		audio.src = `https://ducksdev.eu/sounds/${this.state.selectedSound}.mp3`;

		audio.play();
	}

	isSoundActive(sound) {
		return (sound === this.state.selectedSound)
	}

	changeSound(sound) {
		this.setState({
			selectedSound: sound
		});
	}

	render() {

		if(this.countDrinkOrder() > 0)
			document.title = `(${this.countDrinkOrder()}) Trinken - ${cookies.load("title")}`;

		return(
			<div className="Content">
				<div>
					<div className="Row">
						<Alert variant="secondary">
							<Breadcrumb>
								<Breadcrumb.Item href="/app/overview">
									Übersicht
								</Breadcrumb.Item>
								<Breadcrumb.Item href="/app/kitchen">
									Küche
								</Breadcrumb.Item>
								<Breadcrumb.Item href="/app/kitchen/prepare">
									Zubereitung
								</Breadcrumb.Item>
								<Breadcrumb.Item active>
									Zubereitung Getränke
								</Breadcrumb.Item>
							</Breadcrumb>
						</Alert>
					</div>
					<div className="BadgeRight">
						<Alert variant="secondary">
							<h4>
								<Badge>
									{this.countDrinkOrder()}
								</Badge>
							</h4>
						</Alert>
						<ButtonGroup>
							<Button variant={(this.state.soundOn) ? "success" : "danger"} onClick={() => this.muteSound()}>
								{(this.state.soundOn) ? <FiBell /> : <FiBellOff />}
							</Button>
							<Dropdown as={ButtonGroup}>
								<Dropdown.Toggle variant="dark">
									<FiMusic />
								</Dropdown.Toggle>

								<Dropdown.Menu>
									{this.state.sounds.map((sound, key) => {
										return(
											<Dropdown.Item key={key} active={this.isSoundActive(sound)} onClick={() => this.changeSound(sound)}>
												{sound}
											</Dropdown.Item>
										);
									})}
								</Dropdown.Menu>
							</Dropdown>
						</ButtonGroup>
						
					</div>
				</div>
				
				<Modal show={this.state.showDeleteModal} onHide={() => this.handleDeleteModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Bestellung löschen
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<p>
							Möchten Sie die Bestellen #{this.state.deleteOrderId} wirklich löschen?
						</p>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='dark' onClick={() => this.handleDeleteModal(false)}>
								Abbrechen
							</Button>
							<Button variant='danger' onClick={() => this.saveDeleteOrder()}>
								Löschen
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<div>
					{this.state.isLoading &&
						<Card style={{ display: "inline-flex"}} className="DrinkCard">
							<Card.Header>
								<Placeholder as={Card.Title} animation="glow">
									<Placeholder xs={8} />
								</Placeholder>
								<Placeholder animation="glow">
									<Placeholder xs={6} />
									<br />
									<Placeholder xs={4} />
								</Placeholder>
							</Card.Header>
							<Card.Body>
								<Placeholder variant="secondary" style={{width: '100%'}} as={Alert} animation="glow">
									<FiClock /> <Placeholder xs={3} />
								</Placeholder>
								<Placeholder animation="glow">
									<InputGroup className="OrderInputGroup">
										<InputGroup.Text className="OrderInputGroupText">
											<Placeholder xs={8} />
										</InputGroup.Text>
									</InputGroup>
								</Placeholder>
							</Card.Body>
							<Card.Footer>
								<Placeholder.Button variant="danger" xs={2} />
								<Placeholder.Button variant="success" xs={2} />
							</Card.Footer>
						</Card>
					}
					{this.hasDrinkOrder() &&
						<h1>Keine neuen Bestellungen</h1>
					}
					{ this.state.orderInfo.map((order, key) => {
						let foodOrder = JSON.parse(order.foodOrder);

						this.sendPingIfNewOrder(order.orderTime)

						if (foodOrder.type !== "drinks")
							return null;

						return (
							<Card key={key} style={{ display: "inline-flex"}} className="DrinkCard">
								<Card.Header>
									<Card.Title>
										Bestellung #{order.idOrder}
									</Card.Title>
									<Card.Subtitle>
										<div className="T1">Kellner: {order.name}</div>
										<div className="T1">Tischnummer: {order.idTable}</div>
									</Card.Subtitle>
								</Card.Header>
								<Card.Body>
									<Alert variant={this.checkWaitingTime(order.orderTime)}>
										<b><FiClock /> {this.timestampToTime(order.orderTime)} min</b>
									</Alert>
									{foodOrder.order.map((orderItem, key) => {
										let id = `drink${orderItem.drink.name}${order.idOrder}`;
										return(
											<InputGroup key={key} className="OrderInputGroup">
												<InputGroup.Text className="OrderInputGroupTextDrink">
													{orderItem.drink.name}
												</InputGroup.Text>
												<InputGroup.Text id={id}>
													<b>{orderItem.drink.done} / {orderItem.drink.count}</b>
												</InputGroup.Text>
												<Button size="lg" className="OrderInputGroupButton" variant="success" onClick={() => this.addDrinkButton(id, orderItem.drink.name, order)}>
													<FiPlus />
												</Button>
												<Button size="lg" className="OrderInputGroupButton" variant="danger" onClick={() => this.removeDrinkButton(id, orderItem.drink.name, order)}>
													<FiMinus />
												</Button>
											</InputGroup>
										);
									})}
								</Card.Body>
								<Card.Footer>
									<ButtonGroup>
										<Button size="lg" variant="danger" onClick={() => this.deleteOrder(order.idOrder)}>
											<FiTrash2 />
										</Button>
										<Button size="lg" variant="success" hidden={this.isOrderReady(foodOrder)} onClick={() => this.completeOrder(order.idOrder)}>
											<FiSend />
										</Button>
									</ButtonGroup>
								</Card.Footer>
							</Card>
						);
					})}
				</div>
			</div>
		);
	}
}

export default KitchenDrinks;