import React, { Component } from "react";
import { serverip } from "../config";
import cookies from 'react-cookies';
import { Alert, Breadcrumb, Button, ButtonGroup, Card, InputGroup, Placeholder } from "react-bootstrap";
import './css/Kitchen.css';
import { FiClock, FiTrash2, FiUserCheck } from "react-icons/fi";

class Deliver extends Component {
	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		this.state = {
			orderInfo: [],
			isLoading: true
		}

		document.title = `Ausgabe - ${cookies.load("title")}`;
	}

	componentDidMount() {
		this.refresh();
	}

	refresh() {
		this.getOrder();
		
		setTimeout(() => {
			this.refresh();
		}, 10000);
	}

	async getOrder() {
		await fetch(serverip + "/order/done/all")
        .then(response => response.json())
        .then(data =>{
			this.setState({ 
				orderInfo: data,
				isLoading: false
			 });
		});
	}

	timestampToTime(timestamp) {
		return Number((Date.now() - timestamp) / 1000 / 60).toFixed(0);
	}

	async deliverOrder(idOrder) {
        await fetch(serverip + `/order/done/${idOrder}/2`, {
			method: 'PUT'
		});

        this.getOrder();
    }

	async removeOrder(idOrder) {
		await fetch(serverip + `/order/delete/${idOrder}`, {
			method: "DELETE"
		});

		await fetch(serverip + `/order/hasTable/delete/${idOrder}`, {
			method: "DELETE"
		});

		this.getOrder();
	}

	checkWaitingTime(timestamp) {

		let diff = Number((Date.now() - timestamp) / 1000 / 60).toFixed(0);

		if(diff < 15)
			return "info";
		else if(diff >= 15 && diff < 30)
			return "warning";
		else
			return "danger";
	}

	render() {
		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/kitchen">
							Küche
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Ausgabe
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				{this.state.isLoading && 
					<Card style={{ display: "inline-flex"}} className="FoodCard">
					<Card.Header>
						<Placeholder as={Card.Title} animation="glow">
							<Placeholder xs={4} />
						</Placeholder>
						<Placeholder animation="glow">
							<Placeholder xs={3} />
							<br />
							<Placeholder xs={2} />
						</Placeholder>
					</Card.Header>
					<Card.Body>
						<Placeholder variant="secondary" style={{width: '100%'}} as={Alert} animation="glow">
							<FiClock /> <Placeholder xs={3} />
						</Placeholder>
						<Placeholder animation="glow">
							<InputGroup className="OrderInputGroup">
								<InputGroup.Text className="OrderInputGroupText">
									<Placeholder xs={8} />
								</InputGroup.Text>
							</InputGroup>
						</Placeholder>
					</Card.Body>
					<Card.Footer>
						<Placeholder.Button variant="danger" xs={1} />
						<Placeholder.Button variant="success" xs={1} />
					</Card.Footer>
				</Card>
				}
				{ (this.state.orderInfo.length === 0) &&
					<h1>Keine fertigen Bestellungen</h1>
				}
				{ this.state.orderInfo.map((info, key) => {
					let foodOrder = JSON.parse(info.foodOrder);

					return(
						<Card key={key} style={{ display: "inline-flex"}} className="FoodCard">
							<Card.Header>
								<Card.Title>
									Bestellung #{info.idOrder}
								</Card.Title>
								<Card.Subtitle>
									<div className="T1">Kellner: {info.name}</div>
									<div className="T1">Tischnummer: {info.idTable}</div>
								</Card.Subtitle>
							</Card.Header>
							<Card.Body>
								<Card.Text className="WaitingTime">
									<Alert variant={this.checkWaitingTime(info.orderTime)}>
										<b><FiClock /> {this.timestampToTime(info.orderTime)} min</b>
									</Alert>
								
								{foodOrder.order.map((order, key) => {
									if(order.food !== undefined)
									{
										return(
											<InputGroup key={key} className="OrderInputGroup">
												<InputGroup.Text className="OrderInputGroupText">
													{order.food.name}
												</InputGroup.Text>
												<InputGroup.Text id={"foodNameId"}>
													<b>{order.food.done} / {order.food.count}</b>
												</InputGroup.Text>
												{(order.food.extras !== "") ? 
													<b className="OrderInputExtraText">- {order.food.extras}</b> : null}
											</InputGroup>
										);
									}else {
										return(
											<InputGroup key={key} className="OrderInputGroup">
												<InputGroup.Text className="OrderInputGroupText">
													{order.drink.name}
												</InputGroup.Text>
												<InputGroup.Text id={"foodNameId"}>
													<b>{order.drink.done} / {order.drink.count}</b>
												</InputGroup.Text>
											</InputGroup>
										);
									}
									
								})}
								</Card.Text>
							</Card.Body>
							<Card.Footer>
								<ButtonGroup>
									<Button size="lg" variant="danger" onClick={() => this.removeOrder(info.idOrder)}>
										<FiTrash2 />
									</Button>
									<Button size="lg"  variant="success" onClick={() => this.deliverOrder(info.idOrder)}>
										<FiUserCheck />
									</Button>
								</ButtonGroup>
							</Card.Footer>
						</Card>
					)
				})}
			</div>
		);
	}
}

export default Deliver;