import React, { Component } from 'react';
import { serverip } from "../config";
import cookies from 'react-cookies';
import { Alert, Breadcrumb, Button, Col, Form, InputGroup, Row } from 'react-bootstrap';

class ResturantOverview extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Restaurant Info - ${cookies.load("title")}`;

		this.state = {
			info: [],
			phases: [],
			isLoading: true
		}

	}

	componentDidMount() {
		this.getInfo();
	}

	async getInfo() {
		await fetch(serverip + "/resturant/info")
        .then(response => response.json())
        .then(data =>
			this.setState({ 
				info: data[0],
				isLoading: false
			 })
		);
	}

	async updateInfo() {

		let name = document.getElementById("name").value;

		let json = `{`;
		
		for(let i = 1; i <= 3; i++) {
			json += `"${`phase${i}`}": {"time": ${document.getElementById(`phase${i}Time`).value}, "color": "${document.getElementById(`phase${i}Color`).value.replace('#', '')}"},`;
		}

		json = json.slice(0, -1) + "}";

		await fetch(serverip + `/resturant/update/${name}/${encodeURI(JSON.stringify(json).slice(1, -1))}`, {
			method: "PUT"
		});

		this.getInfo();
	}

	render() {

		let phases = {};

		if(this.state.info.phases !== undefined)
			phases = JSON.parse(this.state.info.phases);

		return(
			<div className='Content'>
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/managment">
							Managment
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Restaurant Info
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Row>
					<Col md={{span: 2}}>
						<Form.Group>
							<Form.Label>
								<h3>
									Restaurant Name
								</h3>
							</Form.Label>
							<Form.Control id="name" defaultValue={this.state.info.name} />
						</Form.Group>
					</Col>
					<Col md={{span: 3, offset: 1}}>
						<Row>
							<Col>
								<h3>
									Wartezeiten
								</h3>
							</Col>
						</Row>
						<Row>
							<Row>
								<Col>
									<Form.Group>
										<InputGroup>
											<Form.Control id='phase1Color' type="color" key={(phases.phase1 !== undefined) ? `#${phases.phase1.color}` : "#0DCAF0"} defaultValue={(phases.phase1 !== undefined) ? `#${phases.phase1.color}` : "#0DCAF0"} />
											<InputGroup.Text>
											Phase 1
											</InputGroup.Text>
											<Form.Control value={0} readOnly />
											<Form.Control value="-" readOnly />
											<Form.Control id='phase1Time' type='number' min={0} max={60} key={(phases.phase1 !== undefined) ? phases.phase1.time : 0} defaultValue={(phases.phase1 !== undefined) ? phases.phase1.time : 0}/>
											<InputGroup.Text>
											Minuten
											</InputGroup.Text>
										</InputGroup>
									</Form.Group>
								</Col>
							</Row>
							<Row>
								<Col>
									<Form.Group>
										<InputGroup>
											<Form.Control id='phase2Color' type="color" key={(phases.phase2 !== undefined) ? `#${phases.phase2.color}` : "#FFC107"} defaultValue={(phases.phase2 !== undefined) ? `#${phases.phase2.color}` : "#FFC107"} />
											<InputGroup.Text>
											Phase 2
											</InputGroup.Text>
											<Form.Control value={(phases.phase1 !== undefined) ? phases.phase1.time : 15} readOnly />
											<Form.Control value="-" readOnly />
											<Form.Control id='phase2Time' type='number' min={0} max={60} key={(phases.phase2 !== undefined) ? phases.phase2.time : 15} defaultValue={(phases.phase2 !== undefined) ? phases.phase2.time : 15}/>
											<InputGroup.Text>
											Minuten
											</InputGroup.Text>
										</InputGroup>
									</Form.Group>
								</Col>
							</Row>
							<Row>
								<Col>
									<Form.Group>
										<InputGroup>
											<Form.Control id='phase3Color' type="color" key={(phases.phase3 !== undefined) ? `#${phases.phase3.color}` : "#DC3545"} defaultValue={(phases.phase3 !== undefined) ? `#${phases.phase3.color}` : "#DC3545"} />
											<InputGroup.Text>
											Phase 3
											</InputGroup.Text>
											<Form.Control value={(phases.phase2 !== undefined) ? phases.phase2.time : 30} readOnly />
											<Form.Control value="-" readOnly />
											<Form.Control id='phase3Time' type='number' value={99} />
											<InputGroup.Text>
											Minuten
											</InputGroup.Text>
										</InputGroup>
									</Form.Group>
								</Col>
							</Row>
						</Row>
					</Col>
				</Row>
				<Row>
					<Col md={2}>
						<Button variant='success' onClick={() => this.updateInfo()}>
							Speichern
						</Button>
					</Col>
				</Row>
			</div>
		);
	}
}

export default ResturantOverview;