import React, { Component } from 'react';
import { Card, Button, Accordion, Badge, ButtonGroup, Modal } from 'react-bootstrap';
import { serverip } from '../config';
import { FiSend, FiTrash2 } from 'react-icons/fi';

import './css/Service.css';

class ServiceTable extends Component {
	constructor() {
		super();

		this.state = {
			orders: [],
			redirect: false,
			showDeleteModal: false,
			deleteOrderId: -1
		}

		this.makeOrder = this.makeOrder.bind(this);
		this.deleteOrderCall = this.deleteOrderCall.bind(this);
		this.deleteOrder = this.deleteOrder.bind(this);
	}

	componentDidMount() {
		this.refresh();
	}

	refresh() {
		this.getTableInfo();

		setTimeout(() => {
			this.refresh();
		}, 10000);
	}

	async getTableInfo() {
        await fetch(serverip + '/table/order/' + this.props.order.idTable)
        .then(response => response.json())
        .then(data => 
            {
                this.setState({ 
						orders: data 
					});
            });
    }

	async deleteOrderCall(idOrder) {
		await fetch(serverip + `/order/delete/${idOrder}`, {
			method: "DELETE"
		});

		await fetch(serverip + `/order/hasTable/delete/${idOrder}`, {
			method: "DELETE"
		});

		this.getTableInfo();
	}

	async completeOrder(idOrder) {
        await fetch(serverip + `/order/done/${idOrder}/2`, {
			method: 'PUT'
		});

        this.getTableInfo();
    }

	checkTime(timestamp) {
		return Number((Date.now() - timestamp) / 1000 / 60).toFixed(0);
	}

	makeOrder() {
		window.location.href = `/app/service/order/${this.props.order.idTable}/${this.props.order.name}/${this.props.order.personCount}`;
    }

	handleDeleteModal(state) {
		this.setState({
			showDeleteModal: state
		});
	}

	saveDeleteOrder() {
		this.deleteOrderCall(this.state.deleteOrderId);

		this.handleDeleteModal(false);
	}

	deleteOrder(idOrder) {
		this.setState({
			deleteOrderId: idOrder
		})

		this.handleDeleteModal(true);
	}

	checkWaitingTime(diff) {
		if(diff < 15)
			return "info";
		else if(diff >= 15 && diff < 30)
			return "warning";
		else
			return "danger";
	}

	render() {
		return(
			<>
			<Modal size='lg' show={this.state.showDeleteModal} onHide={() => this.handleDeleteModal(false)}>
				<Modal.Header closeButton>
					<Modal.Title>
						Bestellung löschen
					</Modal.Title>
				</Modal.Header>
				<Modal.Body>
					<p>
						Möchten Sie die Bestellen #{this.state.deleteOrderId} wirklich löschen?
					</p>
				</Modal.Body>
				<Modal.Footer>
					<ButtonGroup>
						<Button variant='dark' onClick={() => this.handleDeleteModal(false)}>
							Abbrechen
						</Button>
						<Button variant='danger' onClick={() => this.saveDeleteOrder()}>
							Löschen
						</Button>
					</ButtonGroup>
				</Modal.Footer>
			</Modal>
			<Card className="OrderCard">
				<Card.Header>
					Tisch: {this.props.order.name}
					<br />
					Kellner: {this.props.order.waiterName} 
				</Card.Header>
				<Card.Body>
					<Accordion flush>
						{this.state.orders.length === 0 &&
							<div>
								Keine offene Bestellung
							</div>
						}
						{this.state.orders.map((order, key) => {
							let timeDiff = this.checkTime(order.orderTime);
							let foodOrderJson = JSON.parse(order.foodOrder);
							return(
								<Accordion.Item key={key} eventKey={key}>
									<Accordion.Header>
										Bestellungen #{order.idOrder}&nbsp;{ (order.done === 1) ? <Badge bg="success">Fertig</Badge> : null}&nbsp;{<Badge bg={this.checkWaitingTime(timeDiff)}>{timeDiff} min.</Badge>}
									</Accordion.Header>
									<Accordion.Body>
										{foodOrderJson.order.map((order, key) => {
											if(foodOrderJson.type === "food") {
												return(
													<p className='orderListing' key={key}>
														<b>&rsaquo;</b> {order.food.count}x {order.food.name}
														<br />
														{(order.food.extras !== "") ? <small style={{marginLeft: "1rem"}}><b>Extras: </b>{order.food.extras}</small> : null}
													</p>
												);
											}
											else {
												return(
													<p className='orderListing' key={key}>
														<b>&rsaquo;</b> {order.drink.count}x {order.drink.name}
													</p>
												);
											}
										})}
										
										<br />
										<ButtonGroup>
											<Button size='lg' variant='danger' onClick={() => this.deleteOrder(order.idOrder)}>
												<FiTrash2 />
											</Button>
											<Button size='lg' variant='success' hidden={((order.done !== 1))} onClick={() => this.completeOrder(order.idOrder)}>
												<FiSend />
											</Button>
										</ButtonGroup>
									</Accordion.Body>
								</Accordion.Item>
							);
						})}
					</Accordion>
					<br />
					<Button variant="dark" onClick={() => this.makeOrder()}>
						Neue Bestellung
					</Button>
				</Card.Body>
				<Card.Footer>
					Personen: {this.props.order.personCount}
				</Card.Footer>
			</Card>
			</>
		);
	}
}

export default ServiceTable;