import React, { Component } from 'react';
import { serverip } from "../config";
import cookies from 'react-cookies';
import { Alert, Breadcrumb, Button, ButtonGroup, Col, Form, Modal, Placeholder, Row, Table } from 'react-bootstrap';
import { FiCheck, FiEdit, FiTrash2, FiX } from 'react-icons/fi';

class DrinkOverview extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Trinken - ${cookies.load("title")}`;

		this.state = {
			drinks: [],
			showEditModal: false,
			showAddModal: false,
			drink: {idDrink: 0, name: ''},
			isLoading: true
		}

		this.addDrinkCall = this.addDrinkCall.bind(this);
		this.deleteDrinkCall = this.deleteDrinkCall.bind(this);
		this.updateDrinkCall = this.updateDrinkCall.bind(this);
		this.handelEditModal = this.handelEditModal.bind(this);
		this.handelAddModal = this.handelAddModal.bind(this);
		this.addDrink = this.addDrink.bind(this);
		this.editDrink = this.editDrink.bind(this);
		this.updateDrink = this.updateDrink.bind(this);
	}

	componentDidMount() {
		this.getDrinks();
	}

	async getDrinks() {
		await fetch(serverip + "/drinks/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ 
				drinks: data,
				isLoading: false
			 })
		);
	}

	async addDrinkCall(name) {
		await fetch(serverip + "/drinks/add/" + name, {
			method: "POST"
		});

		this.getDrinks();
	}

	async deleteDrinkCall(idDrink) {
		await fetch(serverip + "/drinks/delete/" + idDrink, {
			method: "DELETE"
		});

		this.getDrinks();
	}

	async updateDrinkCall(idDrink, name, isAvailable) {
		await fetch(serverip + `/drinks/update/${idDrink}/${name}/${isAvailable}` , {
			method: "PUT"
		});

		this.getDrinks();
	}

	handelEditModal(state) {
		this.setState({
			showEditModal: state
		});
	}

	editDrink(drink) {
		this.setState({
			drink: drink
		});

		this.handelEditModal(true);
	}

	updateDrink() {
		let idDrink = document.getElementById("editDrinkId").value;
		let name = document.getElementById("editDrinkName").value;
		let isAvailable = document.getElementById("editDrinkIsAvailable").checked;

		this.updateDrinkCall(idDrink, name, isAvailable);

		this.handelEditModal(false);
	}

	handelAddModal(state) {
		this.setState({
			showAddModal: state
		});
	}

	addDrink() {
		this.addDrinkCall(document.getElementById("addDrinkName").value);
		this.handelAddModal(false);
	}

	render() {
		return(
			<div className='Content'>
				<Modal size='lg' show={this.state.showAddModal} onHide={() => this.handelAddModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Trinken hinzufügen
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.addDrink}>
							<Form.Group>
								<Form.Label>Name</Form.Label>
								<Form.Control id="addDrinkName" placeholder='Name' required/>
							</Form.Group>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelAddModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.addDrink}>
								Hinzufügen
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Modal size='lg' show={this.state.showEditModal} onHide={() => this.handelEditModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Trinken bearbeiten
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.updateDrink}>
							<Row>
								<Col>
									<Form.Group>
										<Form.Label>Name</Form.Label>
										<Form.Control id="editDrinkId" value={this.state.drink.idDrink} type='hidden' />
										<Form.Control id="editDrinkName" placeholder='Name' defaultValue={this.state.drink.name} required/>										
									</Form.Group>
								</Col>
								<Col xs={4}>
									<Form.Label>Verfügbar</Form.Label>
									<Form.Check id="editDrinkIsAvailable" type='switch' defaultChecked={this.state.drink.isAvailable} />
								</Col>
							</Row>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelEditModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.updateDrink}>
								Speichern
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/managment">
							Managment
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Trinken
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Button variant='success' onClick={() => this.handelAddModal(true)}>
					Trinken hinzufügen
				</Button>
				<Table>
					<thead>
						<tr>
							<th>
								Name
							</th>
							<th>
								Verfügbar
							</th>
							<th>
								Aktionen
							</th>
						</tr>
					</thead>
					<tbody>
						{this.state.isLoading && 
							<tr>
								<td>
									<Placeholder xs={4} />
								</td>
								<td>
									<Placeholder xs={2} />
								</td>
								<td>
									<Placeholder.Button variant='dark' xs={1} /><Placeholder.Button variant='danger' xs={1} />
								</td>
							</tr>
						}
						{this.state.drinks.map((drink, key) => {
							return(
								<tr key={key}>
									<td>{drink.name}</td>
									<td>{(drink.isAvailable) ? <FiCheck color='green' size={25} /> : <FiX color='red' size={25} />}</td>
									<td>
										<ButtonGroup>
											<Button variant='dark' onClick={() => this.editDrink(drink)}>
												<FiEdit />
											</Button>
											<Button variant='danger' onClick={() => this.deleteDrinkCall(drink.idDrink)}>
												<FiTrash2 />
											</Button>
										</ButtonGroup>
									</td>
								</tr>
							);
						})}
					</tbody>
				</Table>
			</div>
		);
	}
}

export default DrinkOverview;