import React, { Component } from 'react';
import { Breadcrumb, Alert, Container, Row, Col, Button, Modal, ButtonGroup } from 'react-bootstrap';
import cookies from 'react-cookies';
import { serverip } from "../config";
import BarChart from './BarChart';
import DoughnutChart from './DoughnutChart';
import TrafficLight from './TrafficLight';

class Statistics extends Component {
	constructor(props) {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		this.state = {
			info: [],
			orderInfo: [],
			food: [],
			drinks: [],
			tables: [],
			trafficLights: {"info":0, "warning":0, "danger":0, "deliver":0},
			showModal: false,
			corporateColor: "rgba(0,109,132,0.7)",
			colorStatus: ['rgba(196, 23, 0, 0.7)','rgba(0, 3, 196, 0.7)','rgba(14, 135, 0, 0.7)']
		}

		document.title = `Statistiken - ${cookies.load("title")}`;
	}

	componentDidMount() {
		this.refresh();
	}

	refresh() {
		this.getInfo();
		this.getOrder();
		this.getFood();
		this.getDrinks();
		this.getTables();
		
		setTimeout(() => {
			this.refresh();
		}, 30000);
	}

	// Gather Infos

	async getOrder() {
		await fetch(serverip + "/order/all")
        .then(response => response.json())
        .then(data =>{
			this.setState({ orderInfo: data });
			this.countTrafficLight(data)
		});
	}

	async getFood() {
		await fetch(serverip + "/food/all")
        .then(response => response.json())
        .then(data =>{
			this.setState({ food: data });
		});
	}

	async getDrinks() {
		await fetch(serverip + "/drinks/all")
        .then(response => response.json())
        .then(data =>{
			this.setState({ drinks: data });
		});
	}

	async getTables() {
		await fetch(serverip + "/table/all")
        .then(response => response.json())
        .then(data =>{
			this.setState({ tables: data });
		});
	}

	async resetOrder() {
		await fetch(serverip + "/order/reset/", {
			method: 'DELETE'
		});

		this.handleModal(false);
		this.refresh();
	}

	async getInfo() {
		await fetch(serverip + "/resturant/info")
        .then(response => response.json())
        .then(data =>
			this.setState({ 
				info: data[0]
			 })
		);
	}


	// Generate DataSet

	orderPerTableDataSet() {
		let dataSet = {};

		this.state.orderInfo.forEach((orderInfo) => {
			if(dataSet[orderInfo.idTable] === undefined)
				dataSet[orderInfo.idTable] = 1;
			else
				dataSet[orderInfo.idTable] += 1;
		});

		return { label: 'Bestellung per Tisch', data: Object.values(dataSet), backgroundColor: this.getRandomColor(Object.values(dataSet).length),};
	}

	orderPerTableArray() {
		let dataSet = {};

		this.state.orderInfo.forEach((orderInfo) => {
			if(dataSet[orderInfo.idTable] === undefined)
				dataSet[orderInfo.idTable] = 1;
			else
				dataSet[orderInfo.idTable] += 1;
		});

		return Object.values(dataSet);
	}

	foodToDataSet() {
		let dataSet = [];

		this.foodNameToLabel().forEach(foodName => {
			dataSet[foodName] = 0
		});

		this.state.orderInfo.forEach((orderInfo) => {
			let foodOrderJson = JSON.parse(orderInfo.foodOrder);

			if(foodOrderJson.type !== "food")
				return;

			foodOrderJson.order.forEach((foodOrder) => {
				if(dataSet[foodOrder.food.name] === undefined)
					dataSet[foodOrder.food.name] = parseInt(foodOrder.food.count);
				else
					dataSet[foodOrder.food.name] += parseInt(foodOrder.food.count);
			});
		});

		//return {label: '',data: Object.values(dataSet),backgroundColor: this.getRandomColor(Object.values(dataSet).length),};
		return Object.values(dataSet);
	}

	drinksToDataSet() {
		let dataSet = [];

		this.drinkNameToLabel().forEach(drinkName => {
			dataSet[drinkName] = 0
		});

		this.state.orderInfo.forEach((orderInfo) => {
			let foodOrderJson = JSON.parse(orderInfo.foodOrder);

			if(foodOrderJson.type !== "drinks")
				return;

			foodOrderJson.order.forEach((foodOrder) => {
				if(dataSet[foodOrder.drink.name] === undefined)
					dataSet[foodOrder.drink.name] = parseInt(foodOrder.drink.count);
				else
					dataSet[foodOrder.drink.name] += parseInt(foodOrder.drink.count);
			});
		});

		//return {label: '', data: Object.values(dataSet), backgroundColor: this.getRandomColor(Object.values(dataSet).length),};
		return Object.values(dataSet);
	}

	countOrderArray() {
		let counter = {0: 0, 1: 0, 2:0};

		this.state.orderInfo.forEach((order) => {
			counter[order.done] += 1;
		})

		return Object.values(counter);
	}

	countOrderDataSet() {
		let counter = {0: 0, 1: 0, 2:0};

		this.state.orderInfo.forEach((order) => {
			counter[order.done] += 1;
		})

		return {label: 'Bestellstatus', data: Object.values(counter), backgroundColor: this.state.colorStatus,};
	}


	// Total Count

	foodTotal() {
		let totalCount = 0;

		this.state.orderInfo.forEach((order) => {
			let foodOrderJson = JSON.parse(order.foodOrder);

			if(foodOrderJson.type !== "food")
				return;

			foodOrderJson.order.forEach((food) => {
				totalCount += parseInt(food.food.count);
			})
		})

		return totalCount;
	}

	drinksTotal() {
		let totalCount = 0;

		this.state.orderInfo.forEach((order) => {
			let drinkOrderJson = JSON.parse(order.foodOrder);

			if(drinkOrderJson.type !== "drinks")
				return;

				drinkOrderJson.order.forEach((drink) => {
				totalCount += parseInt(drink.drink.count);
			})
		})

		return totalCount;
	}

	countTrafficLight(orderInfo) {
		let trafficLights = {"info":0, "warning":0, "danger":0, "deliver":0}

		orderInfo.forEach((order) => {
			let counter = this.checkWaitingTime(order.orderTime);

			if(order.done === 0)
			{
				switch(counter) {
					case "danger":
						trafficLights.danger += 1;
						break;
					case "warning":
						trafficLights.warning += 1;
						break;
					case "info":
						trafficLights.info += 1;
						break;
					default:
						break;
				}
			}
			else if(order.done === 1)
				trafficLights.deliver += 1;

			
		});

		this.setState({
			trafficLights: trafficLights
		});
	}

	checkWaitingTime(timestamp) {

		let diff = Number((Date.now() - timestamp) / 1000 / 60).toFixed(0);

		if(diff < 15)
			return "info";
		else if(diff >= 15 && diff < 30)
			return "warning";
		else
			return "danger";
	}


	// Generate Labels

	foodNameToLabel() {
		let label = [];

		this.state.food.forEach((food) => {
			label.push(food.name);
		});

		return label
	}

	drinkNameToLabel() {
		let label = [];

		this.state.drinks.forEach((drink) => {
			label.push(drink.name);
		});

		return label
	}

	tableNameToLabel() {
		let label = [];

		this.state.tables.forEach((table) => {
			label.push(`${table.name}`);
		});

		return label
	}

	handleModal(state) {
		this.setState({
			showModal: state
		});
	}

	getRandomColor(number, alpha) {

		let colors = [];

		for(let i = 0; i < number; i++) {
			colors[i] = this.randomRGBa(alpha);
		}

		return colors;
	}

	randomRGBa(alpha) {
		var o = Math.round, r = Math.random, s = 255;
		return 'rgba(' + o(r()*s) + ',' + o(r()*s) + ',' + o(r()*s) + ',' + alpha + ')';
	}

	render() {
		let opactiy = .5;
		let tableColorPlate = this.getRandomColor(this.orderPerTableArray().length, opactiy);

		let phases = {};

		if(this.state.info.phases !== undefined)
			phases = JSON.parse(this.state.info.phases);

		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Statistiken
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Modal size='lg' show={this.state.showModal} onHide={() => this.handleModal(false)}>
					<Modal.Header closeButton>
						Wirklich alle Daten löschen?
					</Modal.Header>
					<Modal.Body>
						<h2>Wollen Sie wirklich <b>ALLE</b> Daten löschen?</h2>
						<p>Dabei werden <b>Aufgenommen, Bearbeitete</b> und <b>fertige</b> Bestellungen gelöscht!</p>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='dark' onClick={() => this.handleModal(false)}>
								Abbrechen
							</Button>
							<Button variant='danger' onClick={() => this.resetOrder()}>
								Zurücksetzten
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Container>
					<Row>
						<Col xs={2}>
							<Button variant='danger' onClick={() => this.handleModal(true)}>
								Zurücksetzten
							</Button>
						</Col>
						<Col>
							<h3>
								Insgesamt {this.foodTotal()} Essen bestellt.
							</h3>
						</Col>
						<Col>
							<h3>
								Insgesamt {this.drinksTotal()} Trinken bestellt.
							</h3>
						</Col>
					</Row>
					<Row>
						<Col>
							<BarChart label={this.foodNameToLabel()} dataSet={this.foodToDataSet()} colorPlate={this.getRandomColor(6, opactiy)} text="Anzahl der bestellten Essen pro Gericht" />
						</Col>
						<Col>
							<BarChart label={this.drinkNameToLabel()} dataSet={this.drinksToDataSet()} colorPlate={this.getRandomColor(8, opactiy)} text="Anzahl der bestellten Trinken pro Getränk" />
						</Col>
						<Col xs={1}>
							<Row>
								<Col style={{backgroundColor: "gray", borderRadius: "0.5rem", paddingTop: "0.5rem", paddingBottom: "0.5rem"}}>
									<TrafficLight bgColor="green" fontColor="black" tooltip="fertig zum ausliefern" count={this.state.trafficLights.deliver}  />
									<TrafficLight key={(phases.length !== undefined) ? `${phases.phase3.color}` : "dc3545"} bgColor={(phases.length !== undefined) ? `#${phases.phase3.color}` : "#dc3545"} fontColor="black" tooltip="warten über 30 min." count={this.state.trafficLights.danger} />
									<TrafficLight bgColor="yellow" fontColor="black" tooltip="warten über 15 min." count={this.state.trafficLights.warning}  />
									<TrafficLight bgColor="lightblue" fontColor="black" tooltip="warten unter 15 min." count={this.state.trafficLights.info}  />
								</Col>
							</Row>
						</Col>
					</Row>
					<br />
					<Row>
						<Col>
							<BarChart label={['Bestellt', 'Zubereitet', 'Serviert']} dataSet={this.countOrderArray()} colorPlate={this.state.colorStatus} text="Status der Bestellungen" />
						</Col>
						<Col>
							<DoughnutChart 
								labels={['In Zubereitung', 'in Auslieferung', 'Serviert']} 
								dataSet={this.countOrderArray()} 
								colorPlate={this.state.colorStatus}
							/>
						</Col>
						<Col>
							<BarChart label={this.tableNameToLabel()} dataSet={this.orderPerTableArray()} text="Bestellungen pro Tisch" colorPlate={tableColorPlate} />
						</Col>
						<Col>
							<DoughnutChart 
								labels={this.tableNameToLabel()} 
								dataSet={this.orderPerTableArray()} 
								colorPlate={tableColorPlate} 
							/>
						</Col>
					</Row>
				</Container>
			</div>
		);
	}
}

export default Statistics;