import React, { Component } from 'react';
import { Form, Button } from 'react-bootstrap';
import cookies from 'react-cookies';

import './css/LoginPage.css';
import { serverip } from '../config';

class LoginPage extends Component {

	constructor(props) {
		super();

		if(cookies.load("username") !== undefined)
			window.location.href = "/app";


		this.login = this.login.bind(this);
		this.handleSubmit = this.handleSubmit.bind(this);

		document.title = `Login - ${cookies.load("title")}`;
	}

	handleSubmit(e) {
		e.preventDefault();
		
		this.login(document.getElementById("username").value);
	}

	async login(username) {
		await fetch(serverip + `/login/check/${username}`)
		.then(response => response.json())
		.then(data => {
			if(data[0].password === document.getElementById("password").value)
			{
				cookies.save("roles", JSON.parse(data[0].roles));
				cookies.save("username", document.getElementById("username").value);
				cookies.save("id", data[0].idWaiter);
				cookies.save("name", data[0].name);
				cookies.save("showOtherTables", false);

				window.location.href = "/app/overview";
			}
			else{
				alert("Wrong username and password")
			}
		});
	}

	render() {
		return(
			<div className="Content">
				<h1>Login</h1>
				<Form className="LoginForm" onSubmit={this.handleSubmit}>
					<Form.Group className="mb-3">
						<Form.Label>
							Username
						</Form.Label>
						<Form.Control id="username" type="text" placeholder="Username" />
					</Form.Group>
					<Form.Group className="mb-3">
						<Form.Label>
							Password
						</Form.Label>
						<Form.Control id="password" type="password" placeholder="Password" />
					</Form.Group>
					<Button variant="dark" type="submit">
						Login
					</Button>
				</Form>
			</div>
		);
	}
}

export default LoginPage;