import React, { Component } from 'react';
import { Breadcrumb, ButtonGroup, Col, ListGroup, Row, Button, InputGroup, FormControl, Accordion, Alert, Badge } from 'react-bootstrap';
import { serverip } from '../config';
import { FiPlus, FiMinus } from 'react-icons/fi';
import cookies from 'react-cookies';

class Order extends Component {

	constructor() {
		super();

		this.state = {
			food: [],
			drink: [],
			typ: -1,
			saved: false
		}

		document.title = `Neue Bestellung - ${cookies.load("title")}`;
	}

	componentDidMount() {
		this.getFood();
		this.getDrink();
	}

	async getFood() {
		await fetch(serverip + "/food/all")
        .then(response => response.json())
        .then(data => this.setState({
				food: data
            })
        );
	}

	async getDrink() {
		await fetch(serverip + "/drinks/all")
        .then(response => response.json())
        .then(data => this.setState({
			drink: data
            })
        );
	}

	addButton(id) {
		let inputId = document.getElementById(id).value;
		document.getElementById(id).value = (parseInt(inputId) + 1);
	}

	removeButton(id) {
		let inputId = document.getElementById(id).value;
		let amount = parseInt(inputId) - 1;
		document.getElementById(id).value = (amount < 0) ? 0 : amount;
	}

	async insertOrder(order) {
        await fetch(serverip + `/order/add/${order}/${Date.now()}`, {
			method: "POST"
		})
		.then(res => res.json())
		.then(order => {
			this.insertOrderTable(order.insertId)
		});
        
        window.location.href = "/app/service";
    }

	async insertOrderTable(idOrder) {
		await fetch(serverip + `/order/table/add/${idOrder}/${this.props.match.params.idTable}`, {
			method: "POST"
		});		
	}

	makeOrder() {
		let order = '';
		let type;

		this.state.food.forEach((item) => {
			let foodInput = document.getElementById("food" + item.name);
			let foodExtra = document.getElementById("foodExtra" + item.name);	

			if(foodInput.value > 0)
			{
				if(type === undefined)
					type = "food";

				order += `{"food": {"name":"${item.name}", "count": "${foodInput.value}", "done":0, "extras":"${foodExtra.value}"}},`;
			}
		});

		if(this.state.typ === 1)
		{
			order = '';
			type = undefined;
		}
			

		this.state.drink.forEach((item) => {
			let drinkInput = document.getElementById("drink" + item.name);

			if(drinkInput.value > 0)
			{
				if(type === undefined)
					type = "drinks";
					
					
				order += `{"drink": {"name":"${item.name}","count":"${drinkInput.value}", "done":0}},`;
			}	
		})

		order = JSON.parse(`{"type":"${(type === "food" || type === "drinks") ? type : "none"}", "order":[${order.slice(0, order.length -1)}]}`);

		if(order.order.length === 0)
			return;
		
		this.insertOrder(encodeURI(JSON.stringify(order)));
	}

	render() {
		return (
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/service">
							Service
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Bestellung
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<h2>{this.props.match.params.name.replace("%20", " ")}</h2>
				<small>Personen: {this.props.match.params.personCount}</small>
				<br /><br />
				<Button variant="success" onClick={()=> { this.makeOrder(); }}>
					Bestellen
				</Button>
				<br /><br />
				<Accordion id="orderTyp" flush>
					<Accordion.Item eventKey="0" onClick={() => this.setState({typ: 0})}>
						<Accordion.Header>
							Essen
						</Accordion.Header>
						<Accordion.Body>
							<ListGroup>
								{this.state.food.map((item, key) => {
									return(
										<ListGroup.Item key={key}>
											<Row> 
												<Col>
													{(item.isAvailable === 0) &&
														<Badge bg="danger" className='Rotate15'>
															Nicht verfügbar
														</Badge>
													}
													{item.name}													
												</Col>
												<Col>
													<InputGroup>
														<FormControl id={"food" + item.name} type="number" defaultValue="0" disabled={!item.isAvailable} />
														<ButtonGroup>
															<Button className='OrderButtonChange' variant="success" disabled={!item.isAvailable} onClick={() => this.addButton("food" + item.name)}>
																<FiPlus />
															</Button>
															<Button className='OrderButtonChange' variant="danger" disabled={!item.isAvailable} onClick={() => this.removeButton("food" + item.name)}>
																<FiMinus />
															</Button>
														</ButtonGroup>
													</InputGroup>
												</Col>
											</Row>
											{(item.isAvailable === 1) &&
												<Row>
													<Col>
														<Accordion defaultActiveKey='closed'>
															<Accordion.Item eventKey="0">
																<Accordion.Header>Extras hinzufügen</Accordion.Header>
																<Accordion.Body>
																<FormControl id={"foodExtra" + item.name} type="text" placeholder='Extras ..' />
																</Accordion.Body>
															</Accordion.Item>
														</Accordion>
													</Col>
												</Row>
											}
										</ListGroup.Item>
									);
								})}
							</ListGroup>
						</Accordion.Body>
					</Accordion.Item>
					<Accordion.Item eventKey="1" onClick={() => this.setState({typ: 1})}>
						<Accordion.Header>
							Trinken
						</Accordion.Header>
						<Accordion.Body>
							<ListGroup>
								{this.state.drink.map((item, key) => {
									return(
										<ListGroup.Item key={key}>
											<Row>
												<Col>
													{(item.isAvailable === 0) &&
														<Badge bg="danger" className='Rotate15'>
															Nicht verfügbar
														</Badge>
													}
													{item.name}
												</Col>
												<Col>
													<InputGroup>
														<FormControl id={"drink" + item.name} type="number" defaultValue="0" disabled={!item.isAvailable} />
														<ButtonGroup>
															<Button className='OrderButtonChange' variant="success" disabled={!item.isAvailable} onClick={() => this.addButton("drink" + item.name)}>
																<FiPlus />
															</Button>
															<Button className='OrderButtonChange' variant="danger" disabled={!item.isAvailable} onClick={() => this.removeButton("drink" + item.name)}>
																<FiMinus />
															</Button>
														</ButtonGroup>
													</InputGroup>
												</Col>
											</Row>
										</ListGroup.Item>
									);
								})}
							</ListGroup>
						</Accordion.Body>
					</Accordion.Item>
				</Accordion>
				<Button variant="success" onClick={()=> { this.makeOrder(); }}>
					Bestellen
				</Button>
				<br /><br />
			</div>
		);
	}
}


export default Order;