import React, { Component } from 'react';
import { serverip } from "../config";
import cookies from 'react-cookies';
import { Alert, Breadcrumb, Button, ButtonGroup, Form, Modal, Placeholder, Table } from 'react-bootstrap';
import { FiEdit, FiTrash2 } from 'react-icons/fi';

class TableOverview extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Tische - ${cookies.load("title")}`;

		this.state = {
			tables: [],
			table: {},
			waiters: [],
			showAddModal: false,
			showEditModal: false,
			isLoading: true
		}

		this.addTable = this.addTable.bind(this);
		this.addTableCall = this.addTableCall.bind(this);
		this.addWaiterToTable = this.addWaiterToTable.bind(this);
		this.updateTableCall = this.updateTableCall.bind(this);
		this.saveEditTable = this.saveEditTable.bind(this);
		this.deleteTable = this.deleteTable.bind(this);
	}

	componentDidMount() {
		this.getTable();
		this.getWaiter();
	}

	async getTable(){
		await fetch(serverip + "/table/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ tables: data })
		);
	}

	async getWaiter() {
		await fetch(serverip + "/waiter/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ 
				waiters: data,
				isLoading: false
			 })
		);
	}

	async addTableCall(personCount, name, idWaiter) {
		await fetch(serverip + `/table/add/${personCount}/${name}`, {
			method: "POST"
		})
		.then(res => res.json())
		.then(table => this.addWaiterToTable(idWaiter, table.insertId));

		this.getTable();
	}

	async updateTableCall(id, personCount, name) {
		await fetch(serverip + `/table/update/${id}/${personCount}/${name}`, {
			method: "PUT"
		});

		this.getTable();
	}

	async addWaiterToTable(idWaiter, idTable) {
		await fetch(serverip + `/waiter/table/add/${idWaiter}/${idTable}`, {
			method: "POST"
		});

		this.getTable();
	}

	async updateWaiterToTable(idWaiter, idTable) {
		await fetch(serverip + `/waiter/table/update/${idWaiter}/${idTable}`, {
			method: "PUT"
		});

		this.getTable();
	}

	async deleteTable(idTable) {
		await fetch(serverip + `/table/delete/${idTable}`, {
			method: "DELETE"
		});

		this.deleteTableHasWaiter(idTable)

		this.getTable();
	}

	async deleteTableHasWaiter(idTable) {
		await fetch(serverip + `/table/hasWaiter/delete/${idTable}`, {
			method: "DELETE"
		});
	}

	handelAddModal(state) {
		this.setState({
			showAddModal: state
		});
	}

	handelEditModal(state) {
		this.setState({
			showEditModal: state
		});
	}

	addTable() {
		let name = document.getElementById("addTableName").value;
		let count = document.getElementById("addTableCount").value;
		let idWaiter = document.getElementById("addTableWaiter").value;

		this.addTableCall(count, name, idWaiter);
		this.handelAddModal(false);
	}

	editTable(table) {
		this.setState({
			table: table
		});

		this.handelEditModal(true);
	}

	saveEditTable() {
		let id = document.getElementById("editTableId").value;
		let name = document.getElementById("editTableName").value;
		let count = document.getElementById("editTableCount").value;
		let waiter = document.getElementById("editTableWaiter").value;

		this.updateTableCall(id, count, name);
		this.updateWaiterToTable(waiter, id);

		this.handelEditModal(false);
	}

	render() {
		return(
			<div className='Content'>
				<Modal size='lg' show={this.state.showAddModal} onHide={() => this.handelAddModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Tisch hinzufügen
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.addTable}>
							<Form.Group>
								<Form.Label>Bezeichnung</Form.Label>
								<Form.Control id="addTableName" placeholder='Name' required/>
							</Form.Group>
							<Form.Group>
								<Form.Label>Anzahl</Form.Label>
								<Form.Control id="addTableCount" type='number' placeholder='1' defaultValue={1} required/>
							</Form.Group>
							<Form.Group>
								<Form.Label>Kellner</Form.Label>
								<Form.Select id="addTableWaiter">
									<option value="-1">Nicht zugewiesen</option>
									{this.state.waiters.map((waiter, key) => {
										return(
											<option key={key} value={waiter.idWaiter}>{waiter.name}</option>
										);
									})}
								</Form.Select>
							</Form.Group>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelAddModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.addTable}>
								Hinzufügen
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Modal size='lg' show={this.state.showEditModal} onHide={() => this.handelEditModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Tisch bearbeiten
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.saveEditTable}>
							<Form.Group>
								<Form.Label>Bezeichnung</Form.Label>
								<Form.Control id="editTableId" type='hidden' value={this.state.table.idTable} />
								<Form.Control id="editTableName" placeholder='Name' defaultValue={this.state.table.name} required/>
							</Form.Group>
							<Form.Group>
								<Form.Label>Anzahl</Form.Label>
								<Form.Control id="editTableCount" type='number' placeholder='0' defaultValue={this.state.table.personCount} required/>
							</Form.Group>
							<Form.Group>
								<Form.Label>Kellner</Form.Label>
								<Form.Select id="editTableWaiter" defaultValue={this.state.table.idWaiter}>
									<option value="-1">Nicht zugewiesen</option>
									{this.state.waiters.map((waiter, key) => {
										return(
											<option key={key} value={waiter.idWaiter}>{waiter.name}</option>
										);
									})}
								</Form.Select>
							</Form.Group>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelEditModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.saveEditTable}>
								Speichern
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/managment">
							Managment
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Tische
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Button variant='success' onClick={() => this.handelAddModal(true)}>
					Tisch hinzufügen
				</Button>
				<Table>
					<thead>
						<tr>
							<th>
								Bezeichnung
							</th>
							<th>
								Sitzplätze
							</th>
							<th>
								Zugewiesener Kellner
							</th>
							<th>
								Aktion
							</th>
						</tr>
					</thead>
					<tbody>
						{this.state.isLoading &&
							<tr>
								<td>
									<Placeholder xs={4} />
								</td>
								<td>
									<Placeholder xs={2} />
								</td>
								<td>
									<Placeholder xs={4} />
								</td>
								<td>
									<Placeholder.Button variant='dark' xs={2} /><Placeholder.Button variant='danger' xs={2} />
								</td>
							</tr>
						}
						{this.state.tables.map((table, key) => {
							return(
								<tr key={key}>
									<td>{table.name}</td>
									<td>{table.personCount}</td>
									<td>{(table.waiterName === null) ? <i>Nicht zugewiesen</i> : table.waiterName}</td>
									<td>
										<ButtonGroup>
											<Button variant='dark' onClick={() => this.editTable(table)}>
												<FiEdit />
											</Button>
											<Button variant='danger' onClick={() => this.deleteTable(table.idTable)}>
												<FiTrash2 />
											</Button>
										</ButtonGroup>
									</td>
								</tr>
							);
						})}
					</tbody>
				</Table>
			</div>
		);
	}
}

export default TableOverview;