import React, { Component } from 'react';
import { Breadcrumb, Alert, Button, Modal, ButtonGroup, Form, Table, Placeholder } from 'react-bootstrap';
import { serverip } from "../config";
import { FiSettings, FiTrash2, FiPrinter } from 'react-icons/fi';
import cookies from 'react-cookies';

class Reservation extends Component {

	constructor() {
		super();

		this.state = {
			showAddModal: false,
			showEditModal: false,
			editReservation: [],
			reservations: [],
			tables: [],
			minSeats: 0,
			maxSeats: 0,
			isLoading: true
		}

		this.addReservationCall = this.addReservationCall.bind(this);
		this.addReservation = this.addReservation.bind(this);

		document.title = `Reservierungen - ${cookies.load("title")}`;
	}

	componentDidMount() {
		this.refresh();
	}

	refresh() {
		this.getTables();
		this.getReservations();
		this.getMaxSeats();
	}

	async getTables() {
		await fetch(serverip + "/table/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ tables: data })
		);
	}
	
	async getMaxSeats() {
		await fetch(serverip + "/reservation/seats")
        .then(response => response.json())
        .then(data => 
			this.setState({ 
				minSeats: data[0].minSeats,
				maxSeats: data[0].maxSeats 
			})
		);
	}

	async getReservations() {
		await fetch(serverip + "/reservation/all")
        .then(response => response.json())
        .then(data =>
			this.setState(
				{ 
					reservations: data,
					isLoading: false
				})
		);
	}

	async addReservationCall(name, count, info, time, table) {
		await fetch(serverip + `/reservation/add/${name}/${count}/${time}/${info}/${table}`, {
			method: "POST"
		});

		this.refresh();
	}

	async deleteReservation(idReservation) {
		await fetch(serverip + `/reservation/delete/${idReservation}`, {
			method: "DELETE"
		});

		this.refresh();
	}

	async updateReservation(name, time, count, info, idTable, idReservation) {
		await fetch(serverip + `/reservation/update/${name}/${count}/${time}/${info}/${idTable}/${idReservation}`, {
			method: "PUT"
		});

		this.handleEditModal(false);
		this.refresh();
	}

	saveReservation() {
		let name = document.getElementById("updateName").value;
		let time = document.getElementById("updateTime").value;
		let count = document.getElementById("updateCount").value;
		let info = document.getElementById("updateInfo").value;
		let idTable = document.getElementById("updateIdTable").value;
		let idReservation = document.getElementById("updateIdReservation").value;

		this.updateReservation(name, time, count, info, idTable, idReservation);
	}

	addReservation() {
		let name = document.getElementById("name").value;
		let count = document.getElementById("personCount").value;
		let info = document.getElementById("info").value;
		let time = document.getElementById("time").value;
		let table = document.getElementById("table").value;

		this.addReservationCall(name, count, info, time, table);
		this.handleAddModal(false);
	}
	
	validatePersonCount(e) {
		document.getElementById('personCountText').innerHTML = `Personen Anzahl: ${e.target.value}`
	}

	handleAddModal(state) {
		this.setState({
			showAddModal: state
		});
	}

	handleEditModal(state) {
		this.setState({
			showEditModal: state
		});
	}

	editReservation(reservation) {
		this.setState({editReservation: reservation}); 
		this.handleEditModal(true);
	}

	getTableName(idTable) {
		let name = "";

		this.state.tables.forEach(table => {
			if(table.idTable === idTable)
				name = table.name;
		});

		return name;
	}

	printTable() {

		var mywindow = window.open('', 'PRINT', 'height=800,width=1000');

		mywindow.document.write('<html><head><title>' + document.title  + '</title>');
		mywindow.document.write('<style>table { border-collapse: collapse; width: 100%} td {border: 1px solid #ddd; padding: 8px} th {padding: 12px; text-align: left; background-color: #04AA6D; color: white} tr:nth-child(even) {background-color: #f2f2f2}</style>')
		mywindow.document.write('</head><body >');
		mywindow.document.write('<h1>' + document.title  + '</h1>');
		mywindow.document.write('<table>');
		mywindow.document.write('<tr><th>Zeit</th><th>Name</th><th>Info</th><th>Anzahl</th><th>Tisch</th></tr>')
		this.state.reservations.forEach((reservation) => {
			mywindow.document.write(`<tr><td>${reservation.time}</td><td>${reservation.name}</td><td>${reservation.info}</td><td>${reservation.count}</td><td>${(reservation.idTable === -1) ? "Noch kein Tisch hinterlegt!" : this.getTableName(reservation.idTable)}</td></tr>`)
		})
		mywindow.document.write('</table></body></html>');

		mywindow.document.close(); // necessary for IE >= 10
		mywindow.focus(); // necessary for IE >= 10*/

		mywindow.print();
		//mywindow.close();

	}

	render() {
		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Reservierungen
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Modal show={this.state.showAddModal} onHide={() => this.handleAddModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Neue Reservierung
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form>
							<Form.Group className="mb-3">
								<Form.Label>
									Name
								</Form.Label>
								<Form.Control id="name" />
							</Form.Group>
							<Form.Group className="mb-3">
								<Form.Label id='personCountText'>
									Personen Anzahl: {this.state.minSeats}
								</Form.Label>
								<Form.Range id="personCount" defaultValue={this.state.minSeats} min={this.state.minSeats} max={this.state.maxSeats} onChange={this.validatePersonCount} />
							</Form.Group>
							<Form.Group className="mb-3">
								<Form.Label>
									Namen alles Gäste
								</Form.Label>
								<Form.Control id="info" as="textarea" />
							</Form.Group>
							<Form.Group className="mb-3">
								<Form.Label>
									Zeit
								</Form.Label>
								<Form.Control id="time" type='time' defaultValue={"18:00"} min={"18:00"} max={"20:00"} step={1800} />
								<span className="validity"></span>
							</Form.Group>
							<Form.Group className='mb-3'>
								<Form.Label>
									Tisch
								</Form.Label>
								<Form.Select id="table">
									<option value={-1}>Tisch später wählen</option>
									{this.state.tables.map((table, key) => {
										return(
											<option key={key} value={table.idTable}>
												{table.name} ({table.personCount} Plätze)
											</option>
										);
									})}
								</Form.Select>
							</Form.Group>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='dark' onClick={() => this.handleAddModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.addReservation}>
								Reservieren
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Modal show={this.state.showEditModal} onHide={() => this.handleEditModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Reservierung bearbeiten
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form>
							<Form.Control id="updateIdReservation" type='hidden' value={this.state.editReservation.idReservation} />
							<Form.Group className="mb-3">
								<Form.Label>
									Name
								</Form.Label>
								<Form.Control id="updateName" defaultValue={this.state.editReservation.name} />
							</Form.Group>
							<Form.Group className="mb-3">
								<Form.Label id='personCountText'>
									Personen Anzahl: {this.state.editReservation.count}
								</Form.Label>
								<Form.Range id="updateCount" defaultValue={this.state.editReservation.count} min={this.state.minSeats} max={this.state.maxSeats} onChange={this.validatePersonCount} />
							</Form.Group>
							<Form.Group className="mb-3">
								<Form.Label>
									Namen alles Gäste
								</Form.Label>
								<Form.Control id="updateInfo" as="textarea" defaultValue={this.state.editReservation.info} />
							</Form.Group>
							<Form.Group className="mb-3">
								<Form.Label>
									Zeit
								</Form.Label>
								<Form.Control id="updateTime" type='time' defaultValue={this.state.editReservation.time} min={"18:00"} max={"20:00"} step={1800} />
								<span className="validity"></span>
							</Form.Group>
							<Form.Group className='mb-3'>
								<Form.Label>
									Tisch
								</Form.Label>
								<Form.Select id="updateIdTable" defaultValue={this.state.editReservation.idTable}>
									<option value={-1}>Tisch später wählen</option>
									{this.state.tables.map((table, key) => {
										return(
											<option key={key} value={table.idTable}>
												{table.name} ({table.personCount} Plätze)
											</option>
										);
									})}
								</Form.Select>
							</Form.Group>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='dark' onClick={() => this.handleEditModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={() => this.saveReservation()}>
								Speichern
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<div>
					<Button variant='dark' onClick={() => this.handleAddModal(true)}>
						Neue Reservierung
					</Button>
					<Button style={{right: "5%", position: "absolute"}} variant='dark' onClick={() => this.printTable()}>
						<FiPrinter />
					</Button>
					<Table id='resTable'>
						<thead>
							<tr>
								<th>
									Zeit
								</th>
								<th>
									Name
								</th>
								<th>
									Anzahl
								</th>
								<th>
									Info
								</th>
								<th>
									Tisch
								</th>
								<th>
									Aktion
								</th>
							</tr>
						</thead>
						<tbody>
							{this.state.isLoading &&
								<tr>
									<td>
										<Placeholder xs={4} />
									</td>
									<td>
										<Placeholder xs={3} /> <Placeholder xs={6} />
									</td>
									<td>
										<Placeholder xs={1} />
									</td>
									<td>
										<Placeholder xs={1} /> <Placeholder xs={2} />, <Placeholder xs={1} /> <Placeholder xs={3} />, <Placeholder xs={3} />
									</td>
									<td>
										<Placeholder xs={5} />
									</td>
									<td>
										<Placeholder.Button variant='dark' xs={2} /><Placeholder.Button variant='danger' xs={2} />
									</td>
								</tr>
							}
							{this.state.reservations.map((reservation, key) => {
								return(
									<tr key={key}>
										<td>
											{reservation.time}
										</td>
										<td>
											{reservation.name}
										</td>
										<td>
											{reservation.count}
										</td>
										<td>
											{reservation.info}
										</td>
										<td>
											{(reservation.idTable === -1) ? "Noch kein Tisch hinterlegt!" : this.getTableName(reservation.idTable)}
										</td>
										<td>
											<ButtonGroup>
												<Button variant='dark' onClick={() => this.editReservation(reservation)}>
													<FiSettings />
												</Button>
												<Button variant='danger' onClick={() => this.deleteReservation(reservation.idReservation)}>
													<FiTrash2 />
												</Button>
											</ButtonGroup>
										</td>
									</tr>
								);
							})}
						</tbody>
					</Table>
				</div>
			</div>
		);
	}
}

export default Reservation;