import React, { Component } from 'react';
import { serverip } from "../config";
import cookies from 'react-cookies';
import { Alert, Breadcrumb, Button, ButtonGroup, Col, Form, Modal, Placeholder, Row, Table } from 'react-bootstrap';
import { FiCheck, FiEdit, FiTrash2, FiX } from 'react-icons/fi';

class FoodOverview extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Essen - ${cookies.load("title")}`;

		this.state = {
			foods: [],
			showEditModal: false,
			showAddModal: false,
			food: {idFood: 0, name: ''},
			isLoading: true
		}

		this.addFoodCall = this.addFoodCall.bind(this);
		this.deleteFoodCall = this.deleteFoodCall.bind(this);
		this.updateFoodCall = this.updateFoodCall.bind(this);
		this.handelEditModal = this.handelEditModal.bind(this);
		this.handelAddModal = this.handelAddModal.bind(this);
		this.addFood = this.addFood.bind(this);
		this.editFood = this.editFood.bind(this);
		this.updateFood = this.updateFood.bind(this);
	}

	componentDidMount() {
		this.getFood();
	}

	async getFood() {
		await fetch(serverip + "/food/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ 
				foods: data,
				isLoading: false
			})
		);
	}

	async addFoodCall(name) {
		await fetch(serverip + "/food/add/" + name, {
			method: "POST"
		});

		this.getFood();
	}

	async deleteFoodCall(idDrink) {
		await fetch(serverip + "/food/delete/" + idDrink, {
			method: "DELETE"
		});

		this.getFood();
	}

	async updateFoodCall(idFood, name, isAvailable) {
		await fetch(serverip + `/food/update/${idFood}/${name}/${isAvailable}` , {
			method: "PUT"
		});

		this.getFood();
	}

	handelEditModal(state) {
		this.setState({
			showEditModal: state
		});
	}

	editFood(food) {
		this.setState({
			food: food
		});

		this.handelEditModal(true);
	}

	updateFood() {
		let idFood = document.getElementById("editFoodId").value;
		let name = document.getElementById("editFoodName").value;
		let isAvailable = document.getElementById("editFoodIsAvailable").checked;

		this.updateFoodCall(idFood, name, isAvailable);

		this.handelEditModal(false);
	}

	handelAddModal(state) {
		this.setState({
			showAddModal: state
		});
	}


	addFood() {
		this.addFoodCall(document.getElementById("addFoodName").value);
		this.handelAddModal(false);
	}

	render() {
		return(
			<div className='Content'>
				<Modal size='lg' show={this.state.showAddModal} onHide={() => this.handelAddModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Essen hinzufügen
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.addFood}>
							<Form.Group>
								<Form.Label>Name</Form.Label>
								<Form.Control id="addFoodName" placeholder='Name' required/>
							</Form.Group>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelAddModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.addFood}>
								Hinzufügen
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Modal size='lg' show={this.state.showEditModal} onHide={() => this.handelEditModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Essen bearbeiten
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.updateFood}>
							<Row>
								<Col>
									<Form.Group>
										<Form.Label>Name</Form.Label>
										<Form.Control id="editFoodId" value={this.state.food.idFood} type='hidden' />
										<Form.Control id="editFoodName" placeholder='Name' defaultValue={this.state.food.name} required/>
									</Form.Group>
								</Col>
								<Col xs={4}>
									<Form.Label>Verfügbar</Form.Label>
									<Form.Check id="editFoodIsAvailable" type='switch' defaultChecked={this.state.food.isAvailable} />
								</Col>
							</Row>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelEditModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.updateFood}>
								Speichern
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/managment">
							Managment
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Trinken
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Button variant='success' onClick={() => this.handelAddModal(true)}>
					Essen hinzufügen
				</Button>
				<Table>
					<thead>
						<tr>
							<th>
								Name
							</th>
							<th>
								Verfügbar
							</th>
							<th>
								Aktionen
							</th>
						</tr>
					</thead>
					<tbody>
						{this.state.isLoading && 
							<tr>
								<td>
									<Placeholder xs={4} />
								</td>
								<td>
									<Placeholder xs={2} />
								</td>
								<td>
									<Placeholder.Button variant='dark' xs={1} /><Placeholder.Button variant='danger' xs={1} />
								</td>
							</tr>
						}
						{this.state.foods.map((food, key) => {
							return(
								<tr key={key}>
									<td>{food.name}</td>
									<td>{(food.isAvailable) ? <FiCheck color='green' size={25} /> : <FiX color='red' size={25} />}</td>
									<td>
										<ButtonGroup>
											<Button variant='dark' onClick={() => this.editFood(food)}>
												<FiEdit />
											</Button>
											<Button variant='danger' onClick={() => this.deleteFoodCall(food.idFood)}>
												<FiTrash2 />
											</Button>
										</ButtonGroup>
									</td>
								</tr>
							);
						})}
					</tbody>
				</Table>
			</div>
		);
	}
}

export default FoodOverview;