import React, { Component } from "react";
import { Alert, Breadcrumb, Button, Card, Col, Row } from "react-bootstrap";
import cookies from 'react-cookies';
import { Textfit } from 'react-textfit';

import "../../css/Dashboard.css";

class KitchenPrepareOverview extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Zubereitung - ${cookies.load("title")}`;
	}

	render() {
		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/kitchen">
							Küche
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Zubereitung
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Row>
					<Col>
						<Card className="DashboardNavCard">
							<Card.Body>
								<Card.Title>
									<Textfit mode="single" forceSingleModeWidth={false}>
										Essen
									</Textfit>
								</Card.Title>
								<Button className="DashboardNavButton" href="/app/kitchen/prepare/food">
									Öffnen
								</Button>
							</Card.Body>
						</Card>
					</Col>
					<Col>
						<Card className="DashboardNavCard">
							<Card.Body>
								<Card.Title>
									<Textfit mode="single" forceSingleModeWidth={false}>
										Getränke
									</Textfit>
								</Card.Title>
								<Button className="DashboardNavButton" href="/app/kitchen/prepare/drinks">
									Öffnen
								</Button>
							</Card.Body>
						</Card>
					</Col>
				</Row>
			</div>
		);
	}
}

export default KitchenPrepareOverview;