import React, { Component } from 'react';
import { serverip } from "./config.js";
import { Col, Container, Row } from 'react-bootstrap';
import cookies from 'react-cookies';

class Menu extends Component {

	constructor() {
		super();

		this.state = {
			drinks: [],
			foods: []
		}

		document.title = `Menu - ${cookies.load("title")}`;
	}

	componentDidMount() {
		this.getDrinks();
		this.getFood();
	}

	async getDrinks() {
		await fetch(serverip + "/drinks/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ drinks: data })
		);
	}

	async getFood() {
		await fetch(serverip + "/food/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ foods: data })
		);
	}

	render() {
		return(
			<div className="Content">
				<Container>
					<Row>
						<Col>
							<h1>Speißekarte</h1>
							<br/><br/>
						</Col>
					</Row>
					<Row>
						<Col>
							<h3>Speißen</h3>
						</Col>
						<Col>
							<h3>Getränke</h3>
						</Col>
					</Row>
					<Row>
						<Col>
							{this.state.foods.map((food, key) => {
								return(
									<li key={key}>{food.name}</li>
								);
							})}
						</Col>
						<Col>
							{this.state.drinks.map((drink, key) => {
								return(
									<li key={key}>{drink.name}</li>
								);
							})}
						</Col>
					</Row>
				</Container>
			</div>
		);
	}
}

export default Menu;