import React, { Component } from 'react';
import { serverip } from "../config";
import cookies from 'react-cookies';
import { Alert, Breadcrumb, Button, ButtonGroup, Col, Container, Form, Modal, Placeholder, Row, Table } from 'react-bootstrap';
import { FiEdit, FiTrash2 } from 'react-icons/fi';

class WaiterOverview extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Mitarbeiter - ${cookies.load("title")}`;

		this.state = {
			waiters: [],
			roles: [],
			showAddModal: false,
			showEditModal: false,
			waiter: {idWaiter: -1, name: "", username: "", password: ""},
			isLoading: true
		}

		this.deleteWaiter = this.deleteWaiter.bind(this);
		this.addWaiterCall = this.addWaiterCall.bind(this);
		this.addWaiter = this.addWaiter.bind(this);
		this.updateWaiterCall = this.updateWaiterCall.bind(this);
		this.editWaiter = this.editWaiter.bind(this);
		this.saveEditWaiter = this.saveEditWaiter.bind(this);
		this.handleSubmitEdit = this.handleSubmitEdit.bind(this);
		this.handleSubmitAdd = this.handleSubmitAdd.bind(this);
	}

	componentDidMount() {
		this.getWaiter();
		this.getRoles();
	}

	async getWaiter(){
		await fetch(serverip + "/waiter/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ waiters: data })
		);
	}

	async getRoles(){
		await fetch(serverip + "/waiter/roles/all")
        .then(response => response.json())
        .then(data =>
			this.setState({ 
				roles: data,
				isLoading: false
			})
		);
	}

	async addWaiterCall(name, username, pw, roles) {
		await fetch(serverip + `/waiter/add/${name}/${username}/${pw}/${roles}`, {
			method: "POST"
		});

		this.getWaiter();
	}

	async updateWaiterCall(idWaiter, name, username, pw, roles) {
		await fetch(serverip + `/waiter/update/${idWaiter}/${name}/${username}/${pw}/${roles}`, {
			method: "PUT"
		});

		this.getWaiter();
		this.handelEditModal(false);
	}

	async deleteWaiterCall(idWaiter) {
		await fetch(serverip + "/waiter/delete/" + idWaiter, {
			method: "DELETE"
		});

		this.getWaiter();
	}

	handelAddModal(state) {
		this.setState({
			showAddModal: state
		});
	}

	addWaiter() {
		let name = document.getElementById("addWaiterName").value;
		let username = document.getElementById("addWaiterUsername").value;
		let pw = document.getElementById("addWaiterPW").value;
		let roleCheckbox = document.getElementsByName("rolesCheckboxAdd");
		let roles = `{"granted":[`;

		roleCheckbox.forEach((role) => {
			if(role.checked)
				roles += role.id + `,`;
		});

		if(roles.substring(roles.length -1) !== '[')
			roles = roles.substring(0, roles.length - 1)

		roles += `]}`;

		this.addWaiterCall(name, username, pw, encodeURI(JSON.stringify(roles)));
		this.handelAddModal(false);
	}

	handelEditModal(state) {
		this.setState({
			showEditModal: state
		});
	}

	editWaiter(waiter) {

		this.setState({
			waiter: waiter
		})

		this.handelEditModal(true);
	}

	saveEditWaiter() {
		let idWaiter = document.getElementById("editWaiterId").value;
		let name = document.getElementById("editWaiterName").value;
		let username = document.getElementById("editWaiterUsername").value;
		let pw = document.getElementById("editWaiterPW").value;
		let roleCheckbox = document.getElementsByName("rolesCheckboxUpdate");
		let roles = `{"granted":[`;

		roleCheckbox.forEach((role) => {
			if(role.checked)
				roles += role.id + `,`;
		});

		if(roles.substring(roles.length -1) !== '[')
			roles = roles.substring(0, roles.length - 1)

		roles += `]}`;

		this.updateWaiterCall(idWaiter, name, username, pw, encodeURI(JSON.stringify(roles)))
	}

	deleteWaiter(waiter) {
		this.deleteWaiterCall(waiter.idWaiter);
	}

	handleSubmitAdd(e) {
		e.preventDefault();

		this.addWaiter();
	}

	handleSubmitEdit(e) {
		e.preventDefault();

		this.editWaiter();
	}

	showRoles(roleJson) {
		let result = "";

		roleJson.forEach(role => {
			this.state.roles.forEach((roleInfo) => {
				if(roleInfo.idRole === role)
					result += `${roleInfo.name}, `;
			});
		});

		return result.substring(0, result.length -2);
	}

	hasRole(roleJson, idRole) {

		if(this.state.waiter.idWaiter === -1)
			return false;

		return JSON.parse(roleJson).granted.includes(idRole);
	}

	render() {
		return(
			<div className='Content'>
				<Modal size='lg' show={this.state.showAddModal} onHide={() => this.handelAddModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Mitarbeiter hinzufügen
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.handleSubmitAdd}>
							<Container>
								<Row>
									<Col>
										<Row>
											<Col>
												<Form.Group className='mb-3'>
													<Form.Label>Name</Form.Label>
													<Form.Control id="addWaiterName" placeholder='Name' required/>
												</Form.Group>
											</Col>
										</Row>
										<Row>
											<Col>
												<Form.Group className='mb-3'>
													<Form.Label>Benutzername</Form.Label>
													<Form.Control id="addWaiterUsername" placeholder='Benutzername' required/>
												</Form.Group>
											</Col>
										</Row>
										<Row>
											<Col>
												<Form.Group className='mb-3'>
													<Form.Label>Passwort</Form.Label>
													<Form.Control id="addWaiterPW" type='password' placeholder='Passwort' required/>
												</Form.Group>
											</Col>
										</Row>
									</Col>
									<Col>
										<Form.Group className='mb-3'>
											<Form.Label>
												Berechtigungen
											</Form.Label>
											{this.state.roles.map((role, key) => {
												return(
													<Form.Check 
														key={key}
														type='checkbox'
														name="rolesCheckboxAdd"
														label={role.name}
														id={role.idRole}
													/>
												);
											})}
										</Form.Group>
									</Col>
								</Row>
							</Container>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelAddModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.addWaiter}>
								Hinzufügen
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Modal size='lg' show={this.state.showEditModal} onHide={() => this.handelEditModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Mitarbeiter bearbeiten
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<Form onSubmit={this.handleSubmitEdit}>
							<Container>
								<Row>
									<Col>
										<Row>
											<Col>
												<Form.Group className='mb-3'>
													<Form.Label>Name</Form.Label>
													<Form.Control id="editWaiterId" type='hidden' defaultValue={this.state.waiter.idWaiter}/>
													<Form.Control id="editWaiterName" placeholder='Name' defaultValue={this.state.waiter.name}/>
												</Form.Group>
											</Col>
										</Row>
										<Row>
											<Col>
												<Form.Group className='mb-3'>
													<Form.Label>Benutzername</Form.Label>
													<Form.Control id="editWaiterUsername" placeholder='Benutzername' defaultValue={this.state.waiter.username}/>
												</Form.Group>
											</Col>
										</Row>
										<Row>
											<Col>
												<Form.Group className='mb-3'>
													<Form.Label>Passwort</Form.Label>
													<Form.Control id="editWaiterPW" type='password' placeholder='Passwort' defaultValue={this.state.waiter.password}/>
												</Form.Group>
											</Col>
										</Row>
									</Col>
									<Col>
										<Form.Group className='mb-3'>
												<Form.Label>
													Berechtigungen
												</Form.Label>
												{this.state.roles.map((role, key) => {
													return(
														<Form.Check 
															key={key}
															type='checkbox'
															name="rolesCheckboxUpdate"
															label={role.name}
															id={role.idRole}
															defaultChecked={this.hasRole(this.state.waiter.roles, role.idRole)}
														/>
													);
												})}
											</Form.Group>
									</Col>
								</Row>
							</Container>
						</Form>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='danger' onClick={() => this.handelEditModal(false)}>
								Abbrechen
							</Button>
							<Button variant='success' onClick={this.saveEditWaiter}>
								Speichern
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item href="/app/managment">
							Managment
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Mitarbeiter
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Button variant='success' onClick={() => this.handelAddModal(true)}>
					Mitarbeiter hinzufügen
				</Button>
				<Table>
					<thead>
						<tr>
							<th>
								Name
							</th>
							<th>
								Benutzername
							</th>
							<th>
								Berechtigungen
							</th>
							<th>
								Aktionen
							</th>
						</tr>
					</thead>
					<tbody>
						{this.state.isLoading &&
							<tr>
								<td>
									<Placeholder xs={4}/>
								</td>
								<td>
									<Placeholder xs={4}/>
								</td>
								<td>
									<Placeholder xs={4}/>
								</td>
								<td>
									<Placeholder.Button variant='dark' xs={4} /><Placeholder.Button variant='danger' xs={4} />
								</td>
							</tr>
						}
						{this.state.waiters.map((waiter, key) => {
							return(
								<tr key={key}>
									<td>{waiter.name}</td>
									<td>{waiter.username}</td>
									<td>{this.showRoles(JSON.parse(waiter.roles).granted)}</td>
									<td>
										<ButtonGroup>
											<Button variant='dark' onClick={() => this.editWaiter(waiter)}>
												<FiEdit />
											</Button>
											<Button variant='danger' onClick={() => this.deleteWaiter(waiter)}>
												<FiTrash2 />
											</Button>
										</ButtonGroup>
									</td>
								</tr>
							);
						})}
					</tbody>
				</Table>
			</div>
		);
	}
}

export default WaiterOverview;