import React, { Component } from "react";
import { Alert, Breadcrumb, Button, Card, Col, Row } from "react-bootstrap";
import cookies from 'react-cookies';
import { Textfit } from 'react-textfit';

import "../../css/Dashboard.css";

class ManagmentOverview extends Component {

	constructor(props) {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Managment - ${cookies.load("title")}`;
	}

	hasRole(roleNumber) {
		return cookies.load("roles").granted.includes(roleNumber);
	}

	render() {
		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Managment
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Row>
					{this.hasRole(7) && 
						<Col md={6}>
							<Card className="DashboardNavCard">
								<Card.Body>
									<Card.Title>
										<Textfit mode="single" forceSingleModeWidth={false}>
											Mitarbeiter
										</Textfit>
									</Card.Title>
									<Button className="DashboardNavButton" href="/app/managment/waiter">
										Öffnen
									</Button>
								</Card.Body>
							</Card>
						</Col>
					}
					{this.hasRole(6) && 
						<Col md={6}>
							<Card className="DashboardNavCard">
								<Card.Body>
									<Card.Title>
										<Textfit mode="single" forceSingleModeWidth={false}>
											Tische
										</Textfit>
									</Card.Title>
									<Button className="DashboardNavButton" href="/app/managment/table">
										Öffnen
									</Button>
								</Card.Body>
							</Card>
						</Col>
					}
				</Row>
				{this.hasRole(5) && 
					<Row>
						<Col md={6}>
							<Card className="DashboardNavCard">
								<Card.Body>
									<Card.Title>
										<Textfit mode="single" forceSingleModeWidth={false}>
											Essen
										</Textfit>
									</Card.Title>
									<Button className="DashboardNavButton" href="/app/managment/food">
										Öffnen
									</Button>
								</Card.Body>
							</Card>
						</Col>
						<Col md={6}>
							<Card className="DashboardNavCard">
								<Card.Body>
									<Card.Title>
										<Textfit mode="single" forceSingleModeWidth={false}>
											Trinken
										</Textfit>
									</Card.Title>
									<Button className="DashboardNavButton" href="/app/managment/drink">
										Öffnen
									</Button>
								</Card.Body>
							</Card>
						</Col>
					</Row>
				}
				{this.hasRole(8) &&
					<Row>
						<Col>
							<Card className="DashboardNavCard">
								<Card.Body>
									<Card.Title>
										<Textfit mode="single" forceSingleModeWidth={false}>
											Restaurant Info
										</Textfit>
									</Card.Title>
									<Button className="DashboardNavButton" href="/app/managment/info">
										Öffnen
									</Button>
								</Card.Body>
							</Card>
						</Col>
					</Row>
				}
			</div>
		);
	}
}

export default ManagmentOverview;