import React, { Component } from "react";
import { Card, Button, InputGroup, Breadcrumb, Alert, ButtonGroup, Modal, Placeholder, Badge, Dropdown} from "react-bootstrap";
import { serverip } from "../config";
import cookies from 'react-cookies';
import { FiTrash2, FiPlus, FiMinus, FiSend, FiClock, FiBellOff, FiBell, FiMusic } from 'react-icons/fi';


class Kitchen extends Component {

	constructor() {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Essen - ${cookies.load("title")}`;

		this.state = {
			orderInfo: [],
			showDeleteModal: false,
			deleteOrderId: -1,
			isLoading: true,
			orderCount: 0,
			currentOrderCount: 0,
			soundOn: true,
			sounds: ['bell', 'chime'],
			selectedSound: 'bell'
		}
		
	}

	componentDidMount() {
		this.refresh();
	}

	refresh() {
		this.getOrder();
		
		setTimeout(() => {
			this.refresh();
		}, 10000);
	}

	playAudio() {
		let audio = new Audio();

		audio.src = `https://ducksdev.eu/sounds/${this.state.selectedSound}.mp3`;

		audio.play();
	}

	async getOrder() {
		await fetch(serverip + "/order/todo/all")
        .then(response => response.json())
        .then(data =>{
			this.setState({orderInfo: []});
			this.setState({ 
				orderInfo: data,
				isLoading: false
			});
		})
		.then(this.countFoodOrder())
	}

	addFoodButton(id, foodName, order) {
		let foodText = document.getElementById(id);
		let json = JSON.parse(order.foodOrder);

		json.order.forEach(food => {
			if(food.food.name === foodName)
				if(food.food.done < food.food.count)
				{
					foodText.innerHTML = `<b>${food.food.done + 1} / ${food.food.count}</b>`;

					food.food.done += 1;
					order.foodOrder = JSON.stringify(json);
					
					this.updateOrderDoing(order.idOrder, JSON.stringify(json));
				}
		});
	}

	removeFoodButton(id, foodName, order) {
		let foodText = document.getElementById(id);
		let json = JSON.parse(order.foodOrder);

		json.order.forEach(food => {
			if(food.food.name === foodName)
				if(food.food.done > 0)
				{
					foodText.innerHTML = `<b>${food.food.done - 1} / ${food.food.count}</b>`;

					food.food.done -= 1;
					order.foodOrder = JSON.stringify(json);
					
					this.updateOrderDoing(order.idOrder, JSON.stringify(json));
				}
		});
	}

	timestampToTime(timestamp) {
		return Math.max(0, Number((Date.now() - timestamp) / 1000 / 60).toFixed(0));
	}

	async updateOrderDoing(idOrder, order) {
		await fetch(serverip + `/order/update/${idOrder}/${encodeURI(order)}`, {
			method: 'PUT'
		});
    }

	async deleteOrderCall(idOrder) {
        await fetch(serverip + "/order/delete/" + idOrder, {
			method: 'DELETE'
		});

		await fetch(serverip + `/order/hasTable/delete/${idOrder}`, {
			method: "DELETE"
		});

		this.getOrder();
    }

	deleteOrder(idOrder) {
		this.setState({
			deleteOrderId: idOrder,
			showDeleteModal: true
		});
    }

	saveDeleteOrder() {
		this.deleteOrderCall(this.state.deleteOrderId);

		this.handleDeleteModal(false);
	}

	isOrderReady(order) {
		let unReady = false;

		order.order.forEach(food => {
			if(parseInt(food.food.done) !== parseInt(food.food.count))
				unReady = true;
		});

		return unReady;
	}

    async completeOrder(idOrder) {
		await fetch(serverip + `/order/done/${idOrder}/1`, {
			method: 'PUT'
		});

        this.getOrder();
    }

	checkWaitingTime(timestamp) {

		let diff = Number((Date.now() - timestamp) / 1000 / 60).toFixed(0);

		if(diff < 15)
			return "info";
		else if(diff >= 15 && diff < 30)
			return "warning";
		else
			return "danger";
	}

	hasFoodOrder() {
		let foodCounter = 0;

		this.state.orderInfo.forEach(order => {

			if(JSON.parse(order.foodOrder).type === "food")
				foodCounter ++;
		});

		return (foodCounter === 0) ? true : false;
	}

	countFoodOrder() {
		let foodCounter = 0;

		this.state.orderInfo.forEach(order => {

			if(JSON.parse(order.foodOrder).type === "food")
				foodCounter ++;
		});

		//if(foodCounter > this.state.orderCount)
		//	this.playAudio();

		this.setState({
			orderCount: foodCounter
		})
	}

	handleDeleteModal(state) {
		this.setState({
			showDeleteModal: state
		});
	}

	sendPingIfNewOrder(timestamp) {

		if(!this.state.soundOn)
			return;

		if(((Date.now() - timestamp) / 1000) < 8) {
			this.playAudio();
		}
	}

	muteSound() {
		let isSoundOn = this.state.soundOn;

		this.setState({
			soundOn: !isSoundOn
		});
	}

	changeSound(sound) {
		this.setState({
			selectedSound: sound
		});
	}

	isSoundActive(sound) {
		return (sound === this.state.selectedSound)
	}

	render() {
		if(this.state.orderCount > 0)
			document.title = `(${this.state.orderCount}) Essen - ${cookies.load("title")}`;

		return(
			<div className="Content">
				<div>
					<div className="Row">
						<Alert variant="secondary">
							<Breadcrumb>
								<Breadcrumb.Item href="/app/overview">
									Übersicht
								</Breadcrumb.Item>
								<Breadcrumb.Item href="/app/kitchen">
									Küche
								</Breadcrumb.Item>
								<Breadcrumb.Item href="/app/kitchen/prepare">
									Zubereitung
								</Breadcrumb.Item>
								<Breadcrumb.Item active>
									Zubereitung Essen
								</Breadcrumb.Item>
							</Breadcrumb>
						</Alert>
					</div>
					<div className="BadgeRight">
						<Alert variant="secondary">
							<h4>
								<Badge>
									{this.state.orderCount}
								</Badge>
							</h4>
						</Alert>
						<ButtonGroup>
							<Button variant={(this.state.soundOn) ? "success" : "danger"} onClick={() => this.muteSound()}>
								{(this.state.soundOn) ? <FiBell /> : <FiBellOff />}
							</Button>
							<Dropdown as={ButtonGroup}>
								<Dropdown.Toggle variant="dark">
									<FiMusic />
								</Dropdown.Toggle>

								<Dropdown.Menu>
									{this.state.sounds.map((sound, key) => {
										return(
											<Dropdown.Item key={key} active={this.isSoundActive(sound)} onClick={() => this.changeSound(sound)}>
												{sound}
											</Dropdown.Item>
										);
									})}
								</Dropdown.Menu>
							</Dropdown>
						</ButtonGroup>
					</div>
				</div>
				<Modal show={this.state.showDeleteModal} onHide={() => this.handleDeleteModal(false)}>
					<Modal.Header closeButton>
						<Modal.Title>
							Bestellung löschen
						</Modal.Title>
					</Modal.Header>
					<Modal.Body>
						<p>
							Möchten Sie die Bestellen #{this.state.deleteOrderId} wirklich löschen?
						</p>
					</Modal.Body>
					<Modal.Footer>
						<ButtonGroup>
							<Button variant='dark' onClick={() => this.handleDeleteModal(false)}>
								Abbrechen
							</Button>
							<Button variant='danger' onClick={() => this.saveDeleteOrder()}>
								Löschen
							</Button>
						</ButtonGroup>
					</Modal.Footer>
				</Modal>
				<div style={{ marginRight: "9%"}}>				
					{this.state.isLoading &&
						<Card style={{ display: "inline-flex"}} className="FoodCard">
							<Card.Header>
								<Placeholder as={Card.Title} animation="glow">
									<Placeholder xs={4} />
								</Placeholder>
								<Placeholder animation="glow">
									<Placeholder xs={2} />
									<br />
									<Placeholder xs={2} />
								</Placeholder>
							</Card.Header>
							<Card.Body>
								<Placeholder variant="secondary" style={{width: '100%'}} as={Alert} animation="glow">
									<FiClock /> <Placeholder xs={3} />
								</Placeholder>
								<Placeholder animation="glow">
									<InputGroup className="OrderInputGroup">
										<InputGroup.Text className="OrderInputGroupText">
											<Placeholder xs={2} />
										</InputGroup.Text>
									</InputGroup>
								</Placeholder>
							</Card.Body>
							<Card.Footer>
								<Placeholder.Button variant="danger" xs={1} />
								<Placeholder.Button variant="success" xs={1} />
							</Card.Footer>
						</Card>
					}
					{ this.hasFoodOrder() &&
						<h1>Keine neuen Bestellungen</h1>
					}
					{ this.state.orderInfo.map((order, key) => {
						let foodOrder = JSON.parse(order.foodOrder);
						this.sendPingIfNewOrder(order.orderTime)
						return(foodOrder.type === "food") ?
						(
							<Card key={key} style={{ display: "inline-flex"}} className="FoodCard">
								<Card.Header>
									<Card.Title>
										Bestellung #{order.idOrder}
									</Card.Title>
									<Card.Subtitle>
										<div className="T1">Kellner: {order.name}</div>
										<div className="T1">Tischnummer: {order.idTable}</div>
									</Card.Subtitle>
								</Card.Header>
								<Card.Body>
									<Alert variant={this.checkWaitingTime(order.orderTime)}>
										<b><FiClock /> {this.timestampToTime(order.orderTime)} min</b>
									</Alert>
									{foodOrder.order.map((orderItem, key) => {
										let id = `food${orderItem.food.name}${order.idOrder}`;
										return(
											<InputGroup key={key} className="OrderInputGroup">
												<InputGroup.Text className="OrderInputGroupText">
													{orderItem.food.name}
												</InputGroup.Text>
												<InputGroup.Text id={id}>
													<b>{orderItem.food.done} / {orderItem.food.count}</b>
												</InputGroup.Text>
												<Button size="lg" className="OrderInputGroupButton" variant="success" onClick={() => this.addFoodButton(id, orderItem.food.name, order)}>
													<FiPlus />
												</Button>
												<Button size="lg" className="OrderInputGroupButton" variant="danger" onClick={() => this.removeFoodButton(id, orderItem.food.name, order)}>
													<FiMinus />
												</Button>
												{(orderItem.food.extras !== "") ? 
													<b className="OrderInputExtraText">&rsaquo; {orderItem.food.extras}</b> : null}
											</InputGroup>
										);
									})}
								</Card.Body>
								<Card.Footer>
									<ButtonGroup>
										<Button size="lg" variant="danger" onClick={() => this.deleteOrder(order.idOrder)}>
											<FiTrash2 />
										</Button>
										<Button size="lg" variant="success" hidden={this.isOrderReady(foodOrder)} onClick={() => this.completeOrder(order.idOrder)}>
											<FiSend />
										</Button>
									</ButtonGroup>
								</Card.Footer>
							</Card>
						): null;
					})}
				</div>
			</div>
		);
	}
}

export default Kitchen;