import React, { Component } from 'react';
import { Breadcrumb, Alert, Card, Placeholder, Button } from 'react-bootstrap';
import ServiceTable from './ServiceTable';
import cookies from 'react-cookies';
import { FiArrowDown, FiEye, FiEyeOff } from "react-icons/fi";


import { serverip } from '../config';
import './css/Service.css';


class Service extends Component {

	constructor() {
		super();

		this.state = {
			tables: [],
			isLoading: true,
			showOtherTables: cookies.load("showOtherTables")
		}

		document.title = `Service - ${cookies.load("title")}`;

		this.handleOtherTables = this.handleOtherTables.bind(this);
	}

	componentDidMount() {
		this.getTables();
	}

	async getTables() {
		await fetch(serverip + "/table/all")
        .then(response => response.json())
        .then(data => this.setState({
				tables: data,
                isLoading: false
            })
        )
	}

	handleOtherTables() {
		let visibility = this.state.showOtherTables;
		
		this.setState({
			showOtherTables: !visibility
		});
	
		cookies.remove("showOtherTables")
		cookies.save("showOtherTables", !visibility);
	}

	render() {
		let counter = 0;
		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item href="/app/overview">
							Übersicht
						</Breadcrumb.Item>
						<Breadcrumb.Item active>
							Service
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				{this.state.isLoading &&
					<Card className="OrderCard">
						<Card.Header>
							<Placeholder animation="glow">
								<Placeholder xs={1} />
								<br />
								<Placeholder xs={2} />
							</Placeholder>
						</Card.Header>
						<Card.Body>
							<Placeholder as={Card.Text} animation="glow">
								<Placeholder xs={2} /> <Placeholder xs={1} />
							</Placeholder>
							<br />
							<Placeholder.Button variant='secondary' xs={2} />
						</Card.Body>
						<Card.Footer>
							<Placeholder animation="glow">
								<Placeholder xs={2} />
							</Placeholder>
						</Card.Footer>
					</Card>
				}
				{ this.state.tables.map((table, key) => {
					
					if(parseInt(table.idWaiter) !== parseInt(cookies.load("id")))
						return "";

					counter ++;

					return(
						<ServiceTable key={key} order={table} />
					);
				})}
				{(counter === 0 && !this.state.isLoading) &&
					<h1>Keine Tische zugewiesen!</h1>
				}
				<hr />
				<h3>
					<Button variant='secondary' onClick={this.handleOtherTables}>
						{!this.state.showOtherTables &&
							<FiEye />
						}
						{this.state.showOtherTables &&
							<FiEyeOff />
						}
					</Button>
					<center>
						<FiArrowDown />Andere Tische<FiArrowDown />
					</center>
				</h3>
				{this.state.tables.map((table, key) => {
					
					if(parseInt(table.idWaiter) === parseInt(cookies.load("id")))
						return "";

					if(this.state.showOtherTables)
						return "";

					return(
						<ServiceTable key={key} order={table} />
					);
				})}
			</div>
		);
	}
}

export default Service;