import React, { Component } from "react";
import { Alert, Breadcrumb, Button, Card, Col, Container, Row } from "react-bootstrap";
import cookies from 'react-cookies';
import { Textfit } from 'react-textfit';

import "../css/Dashboard.css";

class Overview extends Component {

	constructor(props) {
		super();

		if(cookies.load("username") === undefined)
			window.location.href = "/login";

		document.title = `Übersicht - ${cookies.load("title")}`;
	}

	hasRole(roleNumber) {
		return cookies.load("roles").granted.includes(roleNumber);
	}

	render() {
		return(
			<div className="Content">
				<Alert variant="secondary">
					<Breadcrumb>
						<Breadcrumb.Item active>
							Übersicht
						</Breadcrumb.Item>
					</Breadcrumb>
				</Alert>
				<Container>
					<Row>
						{this.hasRole(1) && 
							<Col md={6}>
								<Card className="DashboardNavCard">
									<Card.Body>
										<Card.Title>
											<Textfit mode="single" forceSingleModeWidth={false}>
												Service
											</Textfit>
										</Card.Title>
										<Button className="DashboardNavButton" href="/app/service">
											Öffnen
										</Button>
									</Card.Body>
								</Card>
							</Col>
						}
						{this.hasRole(2) && 
							<Col md={6}>
								<Card className="DashboardNavCard">
									<Card.Body>
										<Card.Title>
											<Textfit mode="single" forceSingleModeWidth={false}>
												Küche
											</Textfit>
										</Card.Title>
										<Button className="DashboardNavButton" href="/app/kitchen">
											Öffnen
										</Button>
									</Card.Body>
								</Card>
							</Col>
						}
					</Row>
					<Row>
						{this.hasRole(3) && 
							<Col md={6}>
								<Card className="DashboardNavCard">
									<Card.Body>
										<Card.Title>
											<Textfit mode="single" forceSingleModeWidth={false}>
												Reservierung <small><em>(Desktop optimiert)</em></small>
											</Textfit>
										</Card.Title>
										<Button className="DashboardNavButton" href="/app/reservation">
											Öffnen
										</Button>
									</Card.Body>
								</Card>
							</Col>
						}
						{this.hasRole(4) && 
							<Col md={6}>
								<Card className="DashboardNavCard">
									<Card.Body>
										<Card.Title>
											<Textfit mode="single" forceSingleModeWidth={false}>
												Statistik <small><em>(Desktop optimiert)</em></small>
											</Textfit>
										</Card.Title>
										<Button className="DashboardNavButton" href="/app/statistics">
											Öffnen
										</Button>
									</Card.Body>
								</Card>
							</Col>
						}
					</Row>
					<Row>
						{(this.hasRole(5) || this.hasRole(6) || this.hasRole(7) || this.hasRole(8)) && 
							<Col md={6}>
								<Card className="DashboardNavCard">
									<Card.Body>
										<Card.Title>
											<Textfit mode="single" forceSingleModeWidth={false}>
												Managment
											</Textfit>
										</Card.Title>
										<Button className="DashboardNavButton" href="/app/managment">
											Öffnen
										</Button>
									</Card.Body>
								</Card>
							</Col>
						}
						<Col md={6}>
							<Card className="DashboardNavCard">
									<Card.Body>
										<Card.Title>
											<Textfit mode="single" forceSingleModeWidth={false}>
												Profil
											</Textfit>
										</Card.Title>
										<Button className="DashboardNavButton" href="/app/profile">
											Öffnen
										</Button>
									</Card.Body>
								</Card>
						</Col>
					</Row>
				</Container>
			</div>
		);
	}
}

export default Overview;